 2→  "name": "code-insights-workspace",
 3→  "private": true,
 4→  "scripts": {
 5→    "build": "pnpm --filter @code-insights/cli build && pnpm --filter @code-insights/server build && pnpm --filter @code-insights/dashboard build",
 6→    "dev": "pnpm --filter @code-insights/cli dev"
 7→  },
 8→  "engines": {
