  1→import * as path from 'path';
  2→import type {
  3→  ParsedSession,
  4→  ParsedMessage,
  5→  SessionCharacter,
  6→  TitleCandidate,
  7→  GeneratedTitle,
  8→} from '../types.js';
  9→
 10→// Skip patterns - generic responses that make poor titles
 11→const SKIP_PATTERNS = [
 12→  /^(yes|no|ok|okay|sure|thanks|thank you|continue|go ahead|sounds good|looks good|perfect|great|nice|cool|done|got it)\.?$/i,
 13→  /^(y|n|k)$/i,
 14→  /^```/,  // Code blocks
 15→];
 16→
 17→// Prefixes to remove from titles
 18→const PREFIX_REMOVALS = [
 19→  /^(help me|can you|could you|please|i want to|i need to|i'd like to|let's)\s+/i,
 20→  /^(hi|hello|hey),?\s*/i,
 21→];
 22→
 23→// Action verbs that indicate good title candidates
 24→const ACTION_VERBS = /^(fix|add|create|build|implement|update|remove|delete|refactor|move|rename|change|modify|setup|configure|install|debug|test|write|make|get|set|find|search|check|review|analyze|optimize|improve|migrate|convert|integrate)/i;
 25→
 26→/**
 27→ * Generate a smart title for a session
 28→ */
 29→export function generateTitle(session: ParsedSession): GeneratedTitle {
 30→  // 1. If Claude Code provided a summary, use it
 31→  if (session.summary && session.summary.trim().length > 0) {
 32→    return {
 33→      title: cleanTitle(session.summary),
 34→      source: 'claude',
 35→      character: null,
 36→    };
 37→  }
 38→
 39→  // 2. Try to extract from first user message
 40→  const userMessageCandidate = extractFromUserMessage(session.messages);
 41→  if (userMessageCandidate && userMessageCandidate.score >= 40) {
 42→    return {
 43→      title: cleanTitle(userMessageCandidate.text),
 44→      source: userMessageCandidate.source,
 45→      character: null,
 46→    };
 47→  }
 48→
 49→  // 3. Try session character-based title
 50→  const character = detectSessionCharacter(session);
 51→  if (character) {
 52→    const characterTitle = generateCharacterTitle(session, character);
 53→    return {
 54→      title: characterTitle,
 55→      source: 'character',
 56→      character,
 57→    };
 58→  }
 59→
 60→  // 4. Use user message even with lower score if available
 61→  if (userMessageCandidate) {
 62→    return {
 63→      title: cleanTitle(userMessageCandidate.text),
 64→      source: userMessageCandidate.source,
 65→      character: null,
 66→    };
 67→  }
 68→
 69→  // 5. Fallback
 70→  return {
 71→    title: `${session.projectName} session (${session.messageCount} messages)`,
 72→    source: 'fallback',
 73→    character: null,
 74→  };
 75→}
 76→
 77→/**
 78→ * Extract title candidate from first meaningful user message
 79→ */
 80→function extractFromUserMessage(messages: ParsedMessage[]): TitleCandidate | null {
 81→  const userMessages = messages.filter(m => m.type === 'user');
 82→
 83→  for (const msg of userMessages.slice(0, 3)) {
 84→    const content = msg.content.trim();
 85→
 86→    if (SKIP_PATTERNS.some(p => p.test(content))) {
 87→      continue;
 88→    }
 89→
 90→    const wordCount = content.split(/\s+/).length;
 91→    if (wordCount < 3) {
 92→      continue;
 93→    }
 94→
 95→    let text = content;
 96→    if (wordCount > 50) {
 97→      const firstSentence = content.split(/[.!?]/)[0];
 98→      text = firstSentence.length > 10 ? firstSentence : content.split(/\s+/).slice(0, 20).join(' ');
 99→    }
100→
101→    const score = scoreUserMessage(text);
102→    if (score > 0) {
103→      return { text, source: 'user_message', score };
104→    }
105→  }
106→
107→  return null;
108→}
109→
110→/**
111→ * Score a user message for title quality
112→ */
113→function scoreUserMessage(text: string): number {
114→  const wordCount = text.split(/\s+/).length;
115→
116→  if (wordCount < 3) return 0;
117→  if (wordCount > 100) return 0;
118→
119→  if (ACTION_VERBS.test(text)) {
120→    if (wordCount >= 5 && wordCount <= 15) return 80;
121→    if (wordCount > 15 && wordCount <= 30) return 70;
122→    return 60;
123→  }
124→
125→  if (text.includes('?')) {
126→    if (wordCount >= 5 && wordCount <= 20) return 70;
127→    return 50;
128→  }
129→
130→  if (wordCount >= 5 && wordCount <= 15) return 60;
131→  if (wordCount > 15 && wordCount <= 50) return 40;
132→
133→  return 20;
134→}
135→
136→/**
137→ * Detect the session's character based on patterns
138→ */
139→export function detectSessionCharacter(session: ParsedSession): SessionCharacter | null {
140→  const { messages, toolCallCount, messageCount } = session;
141→
142→  const toolCounts: Record<string, number> = {};
143→  const filesModified = new Set<string>();
144→  const filesCreated = new Set<string>();
145→
146→  for (const msg of messages) {
147→    for (const tc of msg.toolCalls) {
148→      toolCounts[tc.name] = (toolCounts[tc.name] || 0) + 1;
149→
150→      if (tc.name === 'Edit' || tc.name === 'Write') {
151→        const filePath = tc.input?.file_path as string | undefined;
152→        if (filePath) {
153→          filesModified.add(filePath);
154→          if (tc.name === 'Write') {
155→            filesCreated.add(filePath);
156→          }
157→        }
158→      }
159→    }
160→  }
161→
162→  const editCount = (toolCounts['Edit'] || 0) + (toolCounts['Write'] || 0);
163→  const readCount = (toolCounts['Read'] || 0) + (toolCounts['Grep'] || 0) + (toolCounts['Glob'] || 0);
164→
165→  if (messageCount >= 50 && filesModified.size <= 3 && filesModified.size > 0) {
166→    return 'deep_focus';
167→  }
168→
169→  const hasErrorPatterns = messages.some(m =>
170→    /error|bug|fix|issue|broken|fail/i.test(m.content)
171→  );
172→  const hasFix = messages.some(m =>
173→    /fixed|resolved|working now/i.test(m.content)
174→  );
175→  if (hasErrorPatterns && hasFix && editCount > 0) {
176→    return 'bug_hunt';
177→  }
178→
179→  if (filesCreated.size >= 3) {
180→    return 'feature_build';
181→  }
182→
183→  if (readCount > editCount * 3 && editCount < 5) {
184→    return 'exploration';
185→  }
186→
187→  if (editCount > 10 && filesCreated.size === 0) {
188→    return 'refactor';
189→  }
190→
191→  const questionCount = messages.filter(m =>
192→    m.type === 'user' && m.content.includes('?')
193→  ).length;
194→  if (questionCount >= 3 && toolCallCount < messageCount) {
195→    return 'learning';
196→  }
197→
198→  if (messageCount < 10 && editCount > 0) {
199→    return 'quick_task';
200→  }
201→
202→  return null;
203→}
204→
205→/**
206→ * Generate title based on session character
207→ */
208→function generateCharacterTitle(
209→  session: ParsedSession,
210→  character: SessionCharacter
211→): string {
212→  const fileCounts: Record<string, number> = {};
213→  for (const msg of session.messages) {
214→    for (const tc of msg.toolCalls) {
215→      if (tc.name === 'Edit' || tc.name === 'Write') {
216→        const filePath = tc.input?.file_path as string | undefined;
217→        if (filePath) {
218→          const fileName = path.basename(filePath) || filePath;
219→          fileCounts[fileName] = (fileCounts[fileName] || 0) + 1;
220→        }
221→      }
222→    }
223→  }
224→  const primaryFile = Object.entries(fileCounts)
225→    .sort((a, b) => b[1] - a[1])[0]?.[0] || 'files';
226→
227→  const userContent = session.messages
228→    .filter(m => m.type === 'user')
229→    .map(m => m.content)
230→    .join(' ')
231→    .toLowerCase();
232→
233→  const topic = extractTopic(userContent) || session.projectName;
234→
235→  switch (character) {
236→    case 'deep_focus':
237→      return `Deep work: ${primaryFile}`;
238→    case 'bug_hunt':
239→      return `Fixed: ${extractBugDescription(session.messages) || primaryFile}`;
240→    case 'feature_build':
241→      return `Built: ${topic}`;
242→    case 'exploration':
243→      return `Explored: ${topic}`;
244→    case 'refactor':
245→      return `Refactored: ${primaryFile}`;
246→    case 'learning':
247→      return `Learned: ${topic}`;
248→    case 'quick_task':
249→      return `Updated: ${primaryFile}`;
250→    default:
251→      return `${session.projectName} session`;
252→  }
253→}
254→
255→/**
256→ * Extract a topic from user content
257→ */
258→function extractTopic(content: string): string | null {
259→  const patterns = [
260→    /(?:about|for|with|using)\s+([a-z][a-z0-9\s-]{2,20})/i,
261→    /([a-z][a-z0-9\s-]{2,15})\s+(?:feature|component|module|function|api)/i,
262→  ];
263→
264→  for (const pattern of patterns) {
265→    const match = content.match(pattern);
266→    if (match) {
267→      return match[1].trim();
268→    }
269→  }
270→
271→  return null;
272→}
273→
274→/**
275→ * Extract bug description from messages
276→ */
277→function extractBugDescription(messages: ParsedMessage[]): string | null {
278→  for (const msg of messages) {
279→    if (msg.type === 'user') {
280→      const match = msg.content.match(/(?:fix|bug|error|issue)[:\s]+([^.!?\n]{5,40})/i);
281→      if (match) {
282→        return match[1].trim();
283→      }
284→    }
285→  }
286→  return null;
287→}
288→
289→/**
290→ * Clean and format a title
291→ */
292→export function cleanTitle(raw: string): string {
293→  let title = raw;
294→
295→  for (const pattern of PREFIX_REMOVALS) {
296→    title = title.replace(pattern, '');
297→  }
298→
299→  title = title.replace(/[*_`#]/g, '');
300→  title = title.replace(/\s+/g, ' ').trim();
301→
302→  if (title.length > 60) {
303→    title = title.slice(0, 57) + '...';
304→  }
305→
306→  title = title.charAt(0).toUpperCase() + title.slice(1);
307→
308→  return title;
309→}
310→
311→/**
312→ * Capitalize first letter of string
313→ */
314→function capitalize(str: string): string {
315→  return str.charAt(0).toUpperCase() + str.slice(1);
316→}
317→

  1→import * as fs from 'fs';
  2→import * as path from 'path';
  3→import * as readline from 'readline';
  4→import type {
  5→  JsonlEntry,
  6→  ClaudeMessage,
  7→  SessionSummary,
  8→  ParsedSession,
  9→  ParsedMessage,
 10→  ToolCall,
 11→  ToolResult,
 12→  MessageUsage,
 13→  MessageContent,
 14→  SessionUsage,
 15→} from '../types.js';
 16→import { generateTitle } from './titles.js';
 17→import { calculateCost, type UsageEntry } from '../utils/pricing.js';
 18→
 19→/**
 20→ * Parse a single JSONL file and extract session data
 21→ */
 22→export async function parseJsonlFile(filePath: string): Promise<ParsedSession | null> {
 23→  const entries: JsonlEntry[] = [];
 24→
 25→  const fileStream = fs.createReadStream(filePath);
 26→  const rl = readline.createInterface({
 27→    input: fileStream,
 28→    crlfDelay: Infinity,
 29→  });
 30→
 31→  for await (const line of rl) {
 32→    if (line.trim()) {
 33→      try {
 34→        const entry = JSON.parse(line) as JsonlEntry;
 35→        entries.push(entry);
 36→      } catch {
 37→        // Skip malformed lines
 38→        continue;
 39→      }
 40→    }
 41→  }
 42→
 43→  if (entries.length === 0) {
 44→    return null;
 45→  }
 46→
 47→  return buildSession(filePath, entries);
 48→}
 49→
 50→/**
 51→ * Build a ParsedSession from JSONL entries
 52→ */
 53→function buildSession(filePath: string, entries: JsonlEntry[]): ParsedSession | null {
 54→  // Extract session ID from filename
 55→  const sessionId = extractSessionId(filePath);
 56→  if (!sessionId) return null;
 57→
 58→  // Find summary entries
 59→  const summaries = entries.filter((e): e is SessionSummary => e.type === 'summary');
 60→  const summary = summaries.length > 0 ? summaries[summaries.length - 1].summary : null;
 61→
 62→  // Find all messages
 63→  const messages = entries.filter(
 64→    (e): e is ClaudeMessage =>
 65→      e.type === 'user' || e.type === 'assistant' || e.type === 'system'
 66→  );
 67→
 68→  if (messages.length === 0) {
 69→    return null;
 70→  }
 71→
 72→  // Extract metadata from first message
 73→  const firstMessage = messages[0];
 74→  const projectPath = firstMessage.cwd || extractProjectPath(filePath);
 75→  const projectName = extractProjectName(projectPath);
 76→  const gitBranch = firstMessage.gitBranch || null;
 77→  const claudeVersion = firstMessage.version || null;
 78→
 79→  // Parse all messages
 80→  const parsedMessages: ParsedMessage[] = [];
 81→  let toolCallCount = 0;
 82→  let userMessageCount = 0;
 83→  let assistantMessageCount = 0;
 84→
 85→  for (const msg of messages) {
 86→    // Skip meta messages
 87→    if (msg.isMeta) continue;
 88→
 89→    const parsed = parseMessage(msg, sessionId);
 90→    if (parsed) {
 91→      parsedMessages.push(parsed);
 92→      toolCallCount += parsed.toolCalls.length;
 93→
 94→      if (msg.type === 'user') userMessageCount++;
 95→      if (msg.type === 'assistant') assistantMessageCount++;
 96→    }
 97→  }
 98→
 99→  // Extract usage data from raw messages
100→  const usageEntries: UsageEntry[] = [];
101→  for (const msg of messages) {
102→    if (msg.isMeta) continue;
103→    if (msg.message?.model && msg.message?.usage) {
104→      usageEntries.push({
105→        model: msg.message.model,
106→        usage: msg.message.usage,
107→      });
108→    }
109→  }
110→
111→  // Aggregate usage stats
112→  let usage: SessionUsage | undefined;
113→  if (usageEntries.length > 0) {
114→    const totalInputTokens = usageEntries.reduce((sum, e) => sum + (e.usage.input_tokens ?? 0), 0);
115→    const totalOutputTokens = usageEntries.reduce((sum, e) => sum + (e.usage.output_tokens ?? 0), 0);
116→    const cacheCreationTokens = usageEntries.reduce((sum, e) => sum + (e.usage.cache_creation_input_tokens ?? 0), 0);
117→    const cacheReadTokens = usageEntries.reduce((sum, e) => sum + (e.usage.cache_read_input_tokens ?? 0), 0);
118→
119→    // Count turns per model to find primary model
120→    const modelCounts = new Map<string, number>();
121→    for (const e of usageEntries) {
122→      modelCounts.set(e.model, (modelCounts.get(e.model) ?? 0) + 1);
123→    }
124→    const modelsUsed = [...modelCounts.keys()];
125→    const primaryModel = [...modelsUsed].sort((a, b) =>
126→      (modelCounts.get(b) ?? 0) - (modelCounts.get(a) ?? 0)
127→    )[0] ?? 'unknown';
128→
129→    usage = {
130→      totalInputTokens,
131→      totalOutputTokens,
132→      cacheCreationTokens,
133→      cacheReadTokens,
134→      estimatedCostUsd: calculateCost(usageEntries),
135→      modelsUsed,
136→      primaryModel,
137→      usageSource: 'jsonl',
138→    };
139→  }
140→
141→  if (parsedMessages.length === 0) {
142→    return null;
143→  }
144→
145→  // Get timestamps
146→  const timestamps = parsedMessages.map((m) => m.timestamp.getTime());
147→  const startedAt = new Date(Math.min(...timestamps));
148→  const endedAt = new Date(Math.max(...timestamps));
149→
150→  // Build session object
151→  const session: ParsedSession = {
152→    id: sessionId,
153→    projectPath,
154→    projectName,
155→    summary,
156→    generatedTitle: null,
157→    titleSource: null,
158→    sessionCharacter: null,
159→    startedAt,
160→    endedAt,
161→    messageCount: parsedMessages.length,
162→    userMessageCount,
163→    assistantMessageCount,
164→    toolCallCount,
165→    gitBranch,
166→    claudeVersion,
167→    messages: parsedMessages,
168→    usage,
169→  };
170→
171→  // Generate smart title (no longer depends on insights)
172→  const titleResult = generateTitle(session);
173→
174→  return {
175→    ...session,
176→    generatedTitle: titleResult.title,
177→    titleSource: titleResult.source,
178→    sessionCharacter: titleResult.character,
179→  };
180→}
181→
182→/**
183→ * Parse a single message entry
184→ */
185→function parseMessage(msg: ClaudeMessage, sessionId: string): ParsedMessage | null {
186→  // Skip messages without proper structure
187→  if (!msg.message || !msg.message.content) {
188→    return null;
189→  }
190→
191→  const content = extractTextContent(msg.message.content);
192→  const thinking = extractThinkingContent(msg.message.content);
193→  const toolCalls = extractToolCalls(msg.message.content);
194→  const toolResults = extractToolResults(msg.message.content);
195→
196→  // Skip empty messages (but keep if there's thinking or tool results)
197→  if (!content && toolCalls.length === 0 && !thinking && toolResults.length === 0) {
198→    return null;
199→  }
200→
201→  // Per-message usage (assistant messages only)
202→  let usage: MessageUsage | null = null;
203→  if (msg.type === 'assistant' && msg.message.model && msg.message.usage) {
204→    const u = msg.message.usage;
205→    const model = msg.message.model;
206→    const inputTokens = u.input_tokens ?? 0;
207→    const outputTokens = u.output_tokens ?? 0;
208→    const cacheCreationTokens = u.cache_creation_input_tokens ?? 0;
209→    const cacheReadTokens = u.cache_read_input_tokens ?? 0;
210→
211→    const costEntries = [{ model, usage: u }];
212→    const estimatedCostUsd = calculateCost(costEntries);
213→
214→    usage = {
215→      inputTokens,
216→      outputTokens,
217→      cacheCreationTokens,
218→      cacheReadTokens,
219→      model,
220→      estimatedCostUsd,
221→    };
222→  }
223→
224→  return {
225→    id: msg.uuid,
226→    sessionId,
227→    type: msg.type,
228→    content,
229→    thinking,
230→    toolCalls,
231→    toolResults,
232→    usage,
233→    timestamp: new Date(msg.timestamp),
234→    parentId: msg.parentUuid || null,
235→  };
236→}
