 7→
 8→/** Standard Levenshtein distance between two strings */
 9→export function levenshtein(a: string, b: string): number {
10→  const m = a.length;
11→  const n = b.length;
12→  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
13→
14→  for (let i = 0; i <= m; i++) dp[i][0] = i;
15→  for (let j = 0; j <= n; j++) dp[0][j] = j;
16→
17→  for (let i = 1; i <= m; i++) {
18→    for (let j = 1; j <= n; j++) {
19→      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
20→      dp[i][j] = Math.min(
21→        dp[i - 1][j] + 1,      // deletion
22→        dp[i][j - 1] + 1,      // insertion
23→        dp[i - 1][j - 1] + cost // substitution
24→      );
25→    }
26→  }
27→
28→  return dp[m][n];
29→}
30→
31→/** Returns candidate names within maxDistance, sorted by distance */
32→export function findSimilarNames(input: string, candidates: string[], maxDistance = 3): string[] {
33→  const lower = input.toLowerCase();
34→  return candidates
35→    .map((name) => ({ name, distance: levenshtein(lower, name.toLowerCase()) }))
36→    .filter(({ distance }) => distance <= maxDistance)
37→    .sort((a, b) => a.distance - b.distance)
38→    .map(({ name }) => name);
39→}
