397→// ──────────────────────────────────────────────────────
398→// Main aggregation functions
399→// ──────────────────────────────────────────────────────
400→
401→/**
402→ * High-level overview of all sessions in the period.
403→ */
404→export function computeOverview(
405→  sessions: SessionRow[],
406→  period: Period,
407→): StatsOverview {
408→  const sessionsWithCost = sessions.filter(
409→    (s) => s.estimatedCostUsd != null,
410→  );
411→
412→  const totalCost = sum(sessionsWithCost, (s) => s.estimatedCostUsd!);
413→
414→  const totalTokens = sum(sessionsWithCost, (s) =>
415→    (s.totalInputTokens ?? 0) +
416→    (s.totalOutputTokens ?? 0) +
417→    (s.cacheCreationTokens ?? 0) +
418→    (s.cacheReadTokens ?? 0),
419→  );
420→
421→  const uniqueProjects = new Set(sessions.map((s) => s.projectId));
422→
423→  // Source tools — only populate if 2+ distinct sources exist
424→  const sourceToolNames = sessions
425→    .map((s) => s.sourceTool)
426→    .filter((t): t is string => t != null);
427→  const uniqueSourceTools = new Set(sourceToolNames);
428→  let sourceTools: GroupedMetric[] = [];
429→  if (uniqueSourceTools.size >= 2) {
430→    const groups = groupBy(
431→      sessions.filter((s) => s.sourceTool != null),
432→      (s) => s.sourceTool!,
433→    );
434→    for (const [name, group] of groups) {
435→      sourceTools.push({
436→        name,
437→        count: group.length,
438→        cost: sum(group, (s) => s.estimatedCostUsd ?? 0),
439→        percent:
440→          sessions.length > 0 ? (group.length / sessions.length) * 100 : 0,
441→      });
442→    }
443→    sourceTools.sort((a, b) => b.count - a.count);
444→  }
445→
446→  // Week range: Monday of current week through end of today
447→  const weekStart = startOfWeek();
448→  const tomorrow = today();
449→  tomorrow.setDate(tomorrow.getDate() + 1);
450→
451→  return {
452→    sessionCount: sessions.length,
453→    messageCount: sum(sessions, (s) => s.messageCount),
454→    totalCost,
455→    sessionsWithCostCount: sessionsWithCost.length,
456→    totalTimeMinutes: sum(sessions, (s) => diffMinutes(s.startedAt, s.endedAt)),
457→    totalTokens,
458→    projectCount: uniqueProjects.size,
459→    activityByDay: groupByDay(sessions, period),
460→    todayStats: computeDayStats(sessions, today()),
461→    yesterdayStats: computeDayStats(sessions, yesterday()),
462→    weekStats: computeRangeStats(sessions, weekStart, tomorrow),
463→    topProjects: computeTopProjects(sessions, 5),
464→    sourceTools,
465→  };
466→}
