468→/**
469→ * Detailed cost breakdown across projects, models, and tokens.
470→ */
471→export function computeCostBreakdown(
472→  sessions: SessionRow[],
473→  period: Period,
474→): CostBreakdown {
475→  const costSessions = sessions.filter(
476→    (s) => s.estimatedCostUsd != null,
477→  );
478→  const totalCost = sum(costSessions, (s) => s.estimatedCostUsd!);
479→  const days = daysInPeriod(period, costSessions);
480→  const avgPerDay = days > 0 ? totalCost / days : 0;
481→  const avgPerSession =
482→    costSessions.length > 0 ? totalCost / costSessions.length : 0;
483→
484→  // Daily cost trend
485→  const dailyTrend = groupByDay(sessions, period, 'cost');
486→
487→  // Peak day
488→  let peakDay: CostBreakdown['peakDay'] = null;
489→  if (dailyTrend.length > 0) {
490→    const peak = dailyTrend.reduce((best, pt) =>
491→      pt.value > best.value ? pt : best,
492→    );
493→    if (peak.value > 0) {
494→      // Count sessions on peak day
495→      const peakSessions = sessions.filter(
496→        (s) => bucketKey(s.startedAt, period) === peak.date,
497→      );
498→      peakDay = {
499→        date: peak.date,
500→        cost: peak.value,
501→        sessions: peakSessions.length,
502→      };
503→    }
504→  }
505→
506→  // By project
507→  const projectGroups = groupBy(costSessions, (s) => s.projectName);
508→  const byProject: GroupedMetric[] = [];
509→  for (const [name, group] of projectGroups) {
510→    const cost = sum(group, (s) => s.estimatedCostUsd!);
511→    byProject.push({
512→      name,
513→      count: group.length,
514→      cost,
515→      percent: totalCost > 0 ? (cost / totalCost) * 100 : 0,
516→    });
517→  }
518→  byProject.sort((a, b) => b.cost - a.cost);
519→
520→  // By model
521→  const modelSessions = costSessions.filter((s) => s.primaryModel != null);
522→  const modelGroups = groupBy(modelSessions, (s) => s.primaryModel!);
523→  const byModel: GroupedMetric[] = [];
524→  for (const [name, group] of modelGroups) {
525→    const cost = sum(group, (s) => s.estimatedCostUsd!);
526→    byModel.push({
527→      name,
528→      count: group.length,
529→      cost,
530→      percent: totalCost > 0 ? (cost / totalCost) * 100 : 0,
531→    });
532→  }
533→  byModel.sort((a, b) => b.cost - a.cost);
534→
535→  // Token breakdown with pricing
536→  const inputTokens = sum(costSessions, (s) => s.totalInputTokens ?? 0);
537→  const outputTokens = sum(costSessions, (s) => s.totalOutputTokens ?? 0);
538→  const cacheCreation = sum(costSessions, (s) => s.cacheCreationTokens ?? 0);
539→  const cacheReads = sum(costSessions, (s) => s.cacheReadTokens ?? 0);
540→
541→  // Compute costs using weighted average pricing across models
542→  // For simplicity, use per-session model pricing and sum
543→  let inputCost = 0;
544→  let outputCost = 0;
545→  let cacheCreationCost = 0;
546→  let cacheReadCost = 0;
547→
548→  for (const s of costSessions) {
549→    const pricing = getModelPricing(s.primaryModel ?? '');
550→    inputCost += ((s.totalInputTokens ?? 0) / 1_000_000) * pricing.input;
551→    outputCost += ((s.totalOutputTokens ?? 0) / 1_000_000) * pricing.output;
552→    cacheCreationCost +=
553→      ((s.cacheCreationTokens ?? 0) / 1_000_000) * pricing.input * 1.25;
554→    cacheReadCost +=
555→      ((s.cacheReadTokens ?? 0) / 1_000_000) * pricing.input * 0.1;
556→  }
557→
558→  const cacheDenominator = inputTokens + cacheReads;
559→  const cacheHitRate =
560→    cacheDenominator > 0 ? cacheReads / cacheDenominator : 0;
561→
562→  return {
563→    totalCost,
564→    avgPerDay,
565→    avgPerSession,
566→    sessionCount: sessions.length,
567→    sessionsWithCostCount: costSessions.length,
568→    dailyTrend,
569→    peakDay,
570→    byProject,
571→    byModel,
572→    tokenBreakdown: {
573→      inputTokens,
574→      outputTokens,
575→      cacheCreation,
576→      cacheReads,
577→      inputCost,
578→      outputCost,
579→      cacheCreationCost,
580→      cacheReadCost,
581→      cacheHitRate,
582→    },
583→  };
584→}
