  1→// ──────────────────────────────────────────────────────
  2→// Stats command — Pure aggregation layer
  3→//
  4→// All functions operate on SessionRow[] and produce
  5→// aggregated output types.  Completely data-source agnostic.
  6→// ──────────────────────────────────────────────────────
  7→
  8→import type {
  9→  Period,
 10→  SessionRow,
 11→  StatsOverview,
 12→  CostBreakdown,
 13→  ProjectStatsEntry,
 14→  TodayStats,
 15→  TodaySession,
 16→  ModelStatsEntry,
