 23→// ──────────────────────────────────────────────────────
 24→// Generic helpers
 25→// ──────────────────────────────────────────────────────
 26→
 27→function sum<T>(items: T[], fn: (item: T) => number): number {
 28→  return items.reduce((acc, item) => acc + fn(item), 0);
 29→}
 30→
 31→function diffMinutes(start: Date, end: Date): number {
 32→  return Math.max(0, (end.getTime() - start.getTime()) / 60_000);
 33→}
 34→
 35→function groupBy<T>(items: T[], keyFn: (item: T) => string): Map<string, T[]> {
 36→  const map = new Map<string, T[]>();
 37→  for (const item of items) {
 38→    const key = keyFn(item);
 39→    const group = map.get(key);
 40→    if (group) {
 41→      group.push(item);
 42→    } else {
 43→      map.set(key, [item]);
 44→    }
 45→  }
 46→  return map;
 47→}
 48→
 49→function findMostFrequent(items: string[]): string | undefined {
 50→  if (items.length === 0) return undefined;
 51→  const counts = new Map<string, number>();
 52→  for (const item of items) {
 53→    counts.set(item, (counts.get(item) ?? 0) + 1);
 54→  }
 55→  let best: string | undefined;
 56→  let bestCount = 0;
 57→  for (const [key, count] of counts) {
 58→    if (count > bestCount) {
 59→      best = key;
 60→      bestCount = count;
 61→    }
 62→  }
 63→  return best;
 64→}
