 66→// ──────────────────────────────────────────────────────
 67→// Date helpers
 68→// ──────────────────────────────────────────────────────
 69→
 70→function today(): Date {
 71→  const d = new Date();
 72→  d.setHours(0, 0, 0, 0);
 73→  return d;
 74→}
 75→
 76→function yesterday(): Date {
 77→  const d = today();
 78→  d.setDate(d.getDate() - 1);
 79→  return d;
 80→}
 81→
 82→function startOfWeek(): Date {
 83→  const d = today();
 84→  const day = d.getDay(); // 0=Sun, 1=Mon, ... 6=Sat
 85→  const diff = day === 0 ? 6 : day - 1; // days back to Monday
 86→  d.setDate(d.getDate() - diff);
 87→  return d;
 88→}
