 90→/**
 91→ * Returns the start date for a given period, or undefined for 'all'.
 92→ */
 93→export function periodStartDate(period: Period): Date | undefined {
 94→  const d = today();
 95→  switch (period) {
 96→    case '7d':
 97→      d.setDate(d.getDate() - 7);
 98→      return d;
 99→    case '30d':
100→      d.setDate(d.getDate() - 30);
101→      return d;
102→    case '90d':
103→      d.setDate(d.getDate() - 90);
104→      return d;
105→    case 'all':
106→      return undefined;
107→  }
108→}
