150→// ──────────────────────────────────────────────────────
151→// Time-series helpers
152→// ──────────────────────────────────────────────────────
153→
154→/** Pad a number to 2 digits */
155→function pad2(n: number): string {
156→  return n < 10 ? `0${n}` : `${n}`;
157→}
158→
159→/** Get ISO week number for a date */
160→function isoWeek(d: Date): number {
161→  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
162→  // Set to nearest Thursday: current date + 4 - dayOfWeek (Mon=1, Sun=7)
163→  const dayNum = date.getUTCDay() || 7;
164→  date.setUTCDate(date.getUTCDate() + 4 - dayNum);
165→  const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
166→  return Math.ceil(((date.getTime() - yearStart.getTime()) / 86_400_000 + 1) / 7);
167→}
168→
169→/** Get ISO week year for a date (may differ from calendar year at year boundaries) */
170→function isoWeekYear(d: Date): number {
171→  const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
172→  const dayNum = date.getUTCDay() || 7;
173→  date.setUTCDate(date.getUTCDate() + 4 - dayNum);
174→  return date.getUTCFullYear();
175→}
176→
177→/**
178→ * Returns the bucket key for a given date based on period granularity.
179→ */
180→export function bucketKey(date: Date, period: Period): string {
181→  switch (period) {
182→    case '7d':
183→    case '30d': {
184→      const y = date.getFullYear();
185→      const m = pad2(date.getMonth() + 1);
186→      const d = pad2(date.getDate());
187→      return `${y}-${m}-${d}`;
188→    }
189→    case '90d': {
190→      const wy = isoWeekYear(date);
191→      const wk = isoWeek(date);
192→      return `${wy}-W${pad2(wk)}`;
193→    }
194→    case 'all': {
195→      const y = date.getFullYear();
196→      const m = pad2(date.getMonth() + 1);
197→      return `${y}-${m}`;
198→    }
199→  }
200→}
201→
202→/**
203→ * Create empty time-series buckets for the full date range.
204→ * Uses an optional referenceDate for deterministic testing (defaults to today).
205→ */
206→export function createBuckets(
207→  period: Period,
208→  referenceDate?: Date,
209→): Map<string, TimeSeriesPoint> {
210→  const ref = referenceDate ?? today();
211→  const buckets = new Map<string, TimeSeriesPoint>();
212→
213→  switch (period) {
214→    case '7d': {
215→      for (let i = 6; i >= 0; i--) {
216→        const d = new Date(ref);
217→        d.setDate(d.getDate() - i);
218→        const key = bucketKey(d, period);
219→        buckets.set(key, { date: key, value: 0 });
220→      }
221→      break;
222→    }
223→    case '30d': {
224→      for (let i = 29; i >= 0; i--) {
225→        const d = new Date(ref);
226→        d.setDate(d.getDate() - i);
227→        const key = bucketKey(d, period);
228→        buckets.set(key, { date: key, value: 0 });
229→      }
230→      break;
231→    }
232→    case '90d': {
233→      // 13 weekly buckets ending at the current week
234→      for (let i = 12; i >= 0; i--) {
235→        const d = new Date(ref);
236→        d.setDate(d.getDate() - i * 7);
237→        const key = bucketKey(d, period);
238→        if (!buckets.has(key)) {
239→          buckets.set(key, { date: key, value: 0 });
240→        }
241→      }
242→      break;
243→    }
244→    case 'all': {
245→      // 12 monthly buckets ending at the current month
246→      for (let i = 11; i >= 0; i--) {
247→        const d = new Date(ref.getFullYear(), ref.getMonth() - i, 1);
248→        const key = bucketKey(d, period);
249→        buckets.set(key, { date: key, value: 0 });
250→      }
251→      break;
252→    }
253→  }
254→
255→  return buckets;
256→}
257→
258→/**
259→ * Group sessions into time-series buckets.
260→ * Returns an array sorted oldest-first with gap-filling (zero values).
261→ */
262→export function groupByDay(
263→  sessions: SessionRow[],
264→  period: Period,
265→  metric: 'sessions' | 'cost' | 'tokens' = 'sessions',
266→): TimeSeriesPoint[] {
267→  const buckets = createBuckets(period);
268→
269→  for (const s of sessions) {
270→    const key = bucketKey(s.startedAt, period);
271→    const bucket = buckets.get(key);
272→    if (bucket) {
273→      switch (metric) {
274→        case 'sessions':
275→          bucket.value += 1;
276→          break;
277→        case 'cost':
278→          bucket.value += s.estimatedCostUsd ?? 0;
279→          break;
280→        case 'tokens':
281→          bucket.value +=
282→            (s.totalInputTokens ?? 0) +
283→            (s.totalOutputTokens ?? 0) +
284→            (s.cacheCreationTokens ?? 0) +
285→            (s.cacheReadTokens ?? 0);
286→          break;
287→      }
288→    }
289→  }
290→
291→  // Return sorted oldest-first (Map insertion order is already oldest-first)
292→  return Array.from(buckets.values());
293→}
