295→// ──────────────────────────────────────────────────────
296→// Day / range stats
297→// ──────────────────────────────────────────────────────
298→
299→/**
300→ * Compute stats for sessions starting on a specific calendar day.
301→ */
302→export function computeDayStats(sessions: SessionRow[], dayStart: Date): DayStats {
303→  const dayYear = dayStart.getFullYear();
304→  const dayMonth = dayStart.getMonth();
305→  const dayDate = dayStart.getDate();
306→
307→  const daySessions = sessions.filter((s) => {
308→    const d = s.startedAt;
309→    return (
310→      d.getFullYear() === dayYear &&
311→      d.getMonth() === dayMonth &&
312→      d.getDate() === dayDate
313→    );
314→  });
315→
316→  return {
317→    sessionCount: daySessions.length,
318→    totalCost: sum(daySessions, (s) => s.estimatedCostUsd ?? 0),
319→    totalMinutes: sum(daySessions, (s) => diffMinutes(s.startedAt, s.endedAt)),
320→  };
321→}
322→
323→/**
324→ * Compute stats for sessions in a [from, to) date range.
325→ */
326→export function computeRangeStats(
327→  sessions: SessionRow[],
328→  from: Date,
329→  to: Date,
330→): DayStats {
331→  const fromMs = from.getTime();
332→  const toMs = to.getTime();
333→
334→  const rangeSessions = sessions.filter((s) => {
335→    const t = s.startedAt.getTime();
336→    return t >= fromMs && t < toMs;
337→  });
338→
339→  return {
340→    sessionCount: rangeSessions.length,
341→    totalCost: sum(rangeSessions, (s) => s.estimatedCostUsd ?? 0),
342→    totalMinutes: sum(rangeSessions, (s) => diffMinutes(s.startedAt, s.endedAt)),
343→  };
344→}
