346→// ──────────────────────────────────────────────────────
347→// Top N
348→// ──────────────────────────────────────────────────────
349→
350→/**
351→ * Compute top projects by session count.
352→ */
353→export function computeTopProjects(
354→  sessions: SessionRow[],
355→  limit: number,
356→): GroupedMetric[] {
357→  const groups = groupBy(sessions, (s) => s.projectName);
358→  const total = sessions.length;
359→
360→  const metrics: GroupedMetric[] = [];
361→  for (const [name, group] of groups) {
362→    metrics.push({
363→      name,
364→      count: group.length,
365→      cost: sum(group, (s) => s.estimatedCostUsd ?? 0),
366→      percent: total > 0 ? (group.length / total) * 100 : 0,
367→    });
368→  }
369→
370→  metrics.sort((a, b) => b.count - a.count);
371→  return metrics.slice(0, limit);
372→}
373→
374→// ──────────────────────────────────────────────────────
375→// Helper: number of days in a period
376→// ──────────────────────────────────────────────────────
377→
378→function daysInPeriod(period: Period, sessions: SessionRow[]): number {
379→  switch (period) {
380→    case '7d':
381→      return 7;
382→    case '30d':
383→      return 30;
384→    case '90d':
385→      return 90;
386→    case 'all': {
387→      if (sessions.length === 0) return 1; // avoid division by zero
388→      const dates = sessions.map((s) => s.startedAt.getTime());
389→      const earliest = Math.min(...dates);
390→      const latest = Math.max(...dates);
391→      const days = Math.ceil((latest - earliest) / 86_400_000) + 1;
392→      return Math.max(days, 1);
393→    }
394→  }
395→}
