586→/**
587→ * Per-project statistics.
588→ */
589→export function computeProjectStats(
590→  sessions: SessionRow[],
591→  period: Period,
592→): ProjectStatsEntry[] {
593→  const groups = groupBy(sessions, (s) => s.projectId);
594→  const entries: ProjectStatsEntry[] = [];
595→
596→  for (const [projectId, group] of groups) {
597→    if (group.length === 0) continue;
598→
599→    const models = group
600→      .map((s) => s.primaryModel)
601→      .filter((m): m is string => m != null);
602→    const sourceTools = group
603→      .map((s) => s.sourceTool)
604→      .filter((t): t is string => t != null);
605→
606→    const costSessions = group.filter((s) => s.estimatedCostUsd != null);
607→
608→    entries.push({
609→      projectId,
610→      projectName: group[0].projectName,
611→      sessionCount: group.length,
612→      totalCost: sum(costSessions, (s) => s.estimatedCostUsd!),
613→      totalTimeMinutes: sum(group, (s) => diffMinutes(s.startedAt, s.endedAt)),
614→      messageCount: sum(group, (s) => s.messageCount),
615→      totalTokens: sum(costSessions, (s) =>
616→        (s.totalInputTokens ?? 0) +
617→        (s.totalOutputTokens ?? 0) +
618→        (s.cacheCreationTokens ?? 0) +
619→        (s.cacheReadTokens ?? 0),
620→      ),
621→      primaryModel: findMostFrequent(models),
622→      lastActive: group.reduce(
623→        (latest, s) => (s.endedAt > latest ? s.endedAt : latest),
624→        group[0].endedAt,
625→      ),
626→      sourceTool: findMostFrequent(sourceTools),
627→      activityByDay: groupByDay(group, period),
628→    });
629→  }
630→
631→  entries.sort((a, b) => b.sessionCount - a.sessionCount);
632→  return entries;
633→}
