635→/**
636→ * Today's session details.
637→ */
638→export function computeTodayStats(sessions: SessionRow[]): TodayStats {
639→  const t = today();
640→  const tYear = t.getFullYear();
641→  const tMonth = t.getMonth();
642→  const tDate = t.getDate();
643→
644→  const todaySessions = sessions.filter((s) => {
645→    const d = s.startedAt;
646→    return (
647→      d.getFullYear() === tYear &&
648→      d.getMonth() === tMonth &&
649→      d.getDate() === tDate
650→    );
651→  });
652→
653→  const costSessions = todaySessions.filter(
654→    (s) => s.estimatedCostUsd != null,
655→  );
656→
657→  // Build TodaySession array, sorted by startedAt ASC (chronological)
658→  const sortedSessions = [...todaySessions].sort(
659→    (a, b) => a.startedAt.getTime() - b.startedAt.getTime(),
660→  );
661→
662→  const sessionDetails: TodaySession[] = sortedSessions.map((s) => ({
663→    id: s.id,
664→    projectName: s.projectName,
665→    title: resolveTitle(s),
666→    startedAt: s.startedAt,
667→    endedAt: s.endedAt,
668→    durationMinutes: diffMinutes(s.startedAt, s.endedAt),
669→    cost: s.estimatedCostUsd,
670→    model: s.primaryModel,
671→    messageCount: s.messageCount,
672→    sessionCharacter: s.sessionCharacter,
673→  }));
674→
675→  return {
676→    date: t,
677→    sessionCount: todaySessions.length,
678→    totalCost: sum(costSessions, (s) => s.estimatedCostUsd!),
679→    totalTimeMinutes: sum(todaySessions, (s) =>
680→      diffMinutes(s.startedAt, s.endedAt),
681→    ),
682→    messageCount: sum(todaySessions, (s) => s.messageCount),
683→    totalTokens: sum(costSessions, (s) =>
684→      (s.totalInputTokens ?? 0) +
685→      (s.totalOutputTokens ?? 0) +
686→      (s.cacheCreationTokens ?? 0) +
687→      (s.cacheReadTokens ?? 0),
688→    ),
689→    sessions: sessionDetails,
690→  };
691→}
692→
693→/**
694→ * Per-model statistics.
695→ */
696→export function computeModelStats(
697→  sessions: SessionRow[],
698→  period: Period,
699→): ModelStatsEntry[] {
700→  const withModel = sessions.filter((s) => s.primaryModel != null);
701→  const totalSessions = withModel.length;
702→  const totalCostAll = sum(
703→    withModel.filter((s) => s.estimatedCostUsd != null),
704→    (s) => s.estimatedCostUsd!,
705→  );
706→
707→  const groups = groupBy(withModel, (s) => s.primaryModel!);
708→  const entries: ModelStatsEntry[] = [];
709→
710→  for (const [model, group] of groups) {
711→    const costSessions = group.filter((s) => s.estimatedCostUsd != null);
712→    const modelTotalCost = sum(costSessions, (s) => s.estimatedCostUsd!);
713→    const pricing = getModelPricing(model);
714→
715→    // Per-session token-based cost breakdown
716→    let inputCost = 0;
717→    let outputCost = 0;
718→    let cacheCost = 0;
719→
720→    for (const s of costSessions) {
721→      inputCost += ((s.totalInputTokens ?? 0) / 1_000_000) * pricing.input;
722→      outputCost += ((s.totalOutputTokens ?? 0) / 1_000_000) * pricing.output;
723→      cacheCost +=
724→        ((s.cacheCreationTokens ?? 0) / 1_000_000) * pricing.input * 1.25 +
725→        ((s.cacheReadTokens ?? 0) / 1_000_000) * pricing.input * 0.1;
726→    }
727→
728→    const totalTokens = sum(costSessions, (s) =>
729→      (s.totalInputTokens ?? 0) +
730→      (s.totalOutputTokens ?? 0) +
731→      (s.cacheCreationTokens ?? 0) +
732→      (s.cacheReadTokens ?? 0),
733→    );
734→
735→    entries.push({
736→      model,
737→      displayName: shortenModelName(model),
738→      sessionCount: group.length,
739→      sessionPercent:
740→        totalSessions > 0 ? (group.length / totalSessions) * 100 : 0,
741→      totalCost: modelTotalCost,
742→      costPercent:
743→        totalCostAll > 0 ? (modelTotalCost / totalCostAll) * 100 : 0,
744→      avgCostPerSession:
745→        costSessions.length > 0 ? modelTotalCost / costSessions.length : 0,
746→      totalTokens,
747→      inputCost,
748→      outputCost,
749→      cacheCost,
750→      trend: groupByDay(group, period),
751→    });
752→  }
753→
754→  entries.sort((a, b) => b.totalCost - a.totalCost);
755→  return entries;
756→}
