 3→export function formatMoney(amount: number): string {
 4→  if (amount >= 1000) {
 5→    return '$' + amount.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
 6→  }
 7→  return '$' + amount.toFixed(2);
 8→}
 9→
10→export function formatTokens(count: number): string {
11→  if (count >= 1_000_000) return (count / 1_000_000).toFixed(1) + 'M';
12→  if (count >= 1_000) return Math.round(count / 1_000) + 'K';
13→  return count.toLocaleString();
14→}
15→
16→export function formatDuration(minutes: number): string {
17→  if (minutes < 1) return '< 1m';
18→  if (minutes < 60) return `${Math.round(minutes)}m`;
19→  const h = Math.floor(minutes / 60);
20→  const m = Math.round(minutes % 60);
21→  return m > 0 ? `${h}h ${m}m` : `${h}h`;
22→}
23→
24→export function formatRelativeDate(date: Date): string {
25→  const now = new Date();
26→  const diffMs = now.getTime() - date.getTime();
27→  const diffHours = diffMs / (1000 * 60 * 60);
28→  const diffDays = diffMs / (1000 * 60 * 60 * 24);
29→
30→  if (diffHours < 1) return `${Math.max(1, Math.round(diffMs / 60000))}m ago`;
31→  if (diffHours < 24) return `${Math.round(diffHours)}h ago`;
32→  if (diffDays < 2) return 'yesterday';
33→  if (diffDays < 7) return `${Math.round(diffDays)}d ago`;
34→  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
35→}
36→
37→export function formatTime(date: Date): string {
38→  return date.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true });
39→}
