41→export function formatPercent(value: number): string {
42→  if (value >= 10) return `${Math.round(value)}%`;
43→  return `${value.toFixed(1)}%`;
44→}
45→
46→export function formatCount(count: number): string {
47→  return count.toLocaleString();
48→}
