50→export function formatPeriodLabel(period: Period): string {
51→  switch (period) {
52→    case '7d': return 'Last 7 days';
53→    case '30d': return 'Last 30 days';
54→    case '90d': return 'Last 90 days';
55→    case 'all': return 'All time';
