 3→ * Virtual paths use '#' delimiter: "/path/to/state.vscdb#composerId"
 4→ * Regular paths pass through unchanged.
 5→ */
 6→export function splitVirtualPath(filePath: string): { realPath: string; sessionFragment: string | null } {
