 1→import Database from 'better-sqlite3';
 2→import { join } from 'path';
 3→import { homedir } from 'os';
 4→import { mkdirSync, existsSync } from 'fs';
 5→import { runMigrations } from './migrate.js';
 6→
 7→const DB_DIR = join(homedir(), '.code-insights');
 8→const DB_PATH = join(DB_DIR, 'data.db');
 9→
10→let _db: Database.Database | null = null;
11→
12→/**
13→ * Get (or initialize) the singleton SQLite database instance.
14→ * WAL mode is enabled for concurrent reads during CLI sync.
15→ * Migrations run automatically on first call.
16→ */
17→export function getDb(): Database.Database {
18→  if (_db) return _db;
19→
20→  if (!existsSync(DB_DIR)) {
21→    mkdirSync(DB_DIR, { recursive: true, mode: 0o700 });
22→  }
23→
24→  const db = new Database(DB_PATH);
25→
26→  // WAL mode: allows concurrent reads while CLI writes
27→  db.pragma('journal_mode = WAL');
28→  // Wait up to 5s if another writer holds the lock (e.g., dashboard writing insights)
29→  db.pragma('busy_timeout = 5000');
30→  // Foreign key enforcement
31→  db.pragma('foreign_keys = ON');
32→
33→  runMigrations(db);
34→
35→  _db = db;
36→
37→  // Ensure WAL checkpoint runs on process exit so no data is left in the WAL file.
38→  // Registered here (on first open) so it fires whether process exits normally or
39→  // via an unhandled exception that reaches the exit handler.
40→  process.on('exit', () => {
41→    closeDb();
42→  });
43→
44→  return _db;
45→}
46→
47→/**
48→ * Close the database connection. Used in tests and graceful shutdown.
49→ * Also called by the process 'exit' handler to ensure WAL checkpointing.
50→ */
51→export function closeDb(): void {
52→  if (_db) {
53→    _db.close();
54→    _db = null;
55→  }
56→}
57→
58→/**
59→ * Get the database file path.
60→ */
61→export function getDbPath(): string {
62→  return DB_PATH;
63→}
