 29→let _stmtUpsertProjectBase: BetterSqlite3.Statement | null = null;
 30→let _stmtUpdateProjectWithUsage: BetterSqlite3.Statement | null = null;
 31→let _stmtUpdateProjectCountOnly: BetterSqlite3.Statement | null = null;
 32→let _stmtUpsertSession: BetterSqlite3.Statement | null = null;
 33→let _stmtInsertMessage: BetterSqlite3.Statement | null = null;
 34→let _stmtUpsertUsageStatsIncrement: BetterSqlite3.Statement | null = null;
 35→
 36→function getStmts() {
 37→  const db = getDb();
 38→  // If the DB instance changed (test isolation, reset), rebuild all statements
 39→  if (db !== _lastDb) {
 40→    _lastDb = db;
 41→    _stmtUpsertProjectBase = null;
 42→    _stmtUpdateProjectWithUsage = null;
 43→    _stmtUpdateProjectCountOnly = null;
 44→    _stmtUpsertSession = null;
 45→    _stmtInsertMessage = null;
 46→    _stmtUpsertUsageStatsIncrement = null;
 47→  }
 48→
 49→  if (!_stmtUpsertProjectBase) {
 50→    _stmtUpsertProjectBase = db.prepare(`
 51→      INSERT INTO projects (id, name, path, git_remote_url, project_id_source, last_activity)
 52→      VALUES (?, ?, ?, ?, ?, ?)
 53→      ON CONFLICT(id) DO UPDATE SET
 54→        name = excluded.name,
 55→        path = excluded.path,
 56→        git_remote_url = excluded.git_remote_url,
 57→        last_activity = MAX(last_activity, excluded.last_activity),
 58→        updated_at = datetime('now')
 59→    `);
 60→  }
 61→
 62→  if (!_stmtUpdateProjectWithUsage) {
 63→    _stmtUpdateProjectWithUsage = db.prepare(`
 64→      UPDATE projects SET
 65→        session_count         = session_count + 1,
 66→        total_input_tokens    = total_input_tokens + ?,
 67→        total_output_tokens   = total_output_tokens + ?,
 68→        cache_creation_tokens = cache_creation_tokens + ?,
 69→        cache_read_tokens     = cache_read_tokens + ?,
 70→        estimated_cost_usd    = estimated_cost_usd + ?,
 71→        updated_at            = datetime('now')
 72→      WHERE id = ?
 73→    `);
 74→  }
 75→
 76→  if (!_stmtUpdateProjectCountOnly) {
 77→    _stmtUpdateProjectCountOnly = db.prepare(`
 78→      UPDATE projects SET session_count = session_count + 1, updated_at = datetime('now')
 79→      WHERE id = ?
 80→    `);
 81→  }
 82→
 83→  if (!_stmtUpsertSession) {
 84→    _stmtUpsertSession = db.prepare(`
 85→      INSERT INTO sessions (
 86→        id, project_id, project_name, project_path, git_remote_url,
 87→        summary, generated_title, title_source, session_character,
 88→        started_at, ended_at,
 89→        message_count, user_message_count, assistant_message_count, tool_call_count,
 90→        git_branch, claude_version, source_tool,
 91→        device_id, device_hostname, device_platform,
 92→        total_input_tokens, total_output_tokens, cache_creation_tokens, cache_read_tokens,
 93→        estimated_cost_usd, models_used, primary_model, usage_source
 94→      ) VALUES (
 95→        ?, ?, ?, ?, ?,
 96→        ?, ?, ?, ?,
 97→        ?, ?,
 98→        ?, ?, ?, ?,
 99→        ?, ?, ?,
100→        ?, ?, ?,
101→        ?, ?, ?, ?,
102→        ?, ?, ?, ?
103→      )
104→      ON CONFLICT(id) DO UPDATE SET
105→        generated_title         = excluded.generated_title,
106→        title_source            = excluded.title_source,
107→        session_character       = excluded.session_character,
108→        ended_at                = excluded.ended_at,
109→        summary                 = excluded.summary,
110→        message_count           = excluded.message_count,
111→        user_message_count      = excluded.user_message_count,
112→        assistant_message_count = excluded.assistant_message_count,
113→        tool_call_count         = excluded.tool_call_count,
114→        total_input_tokens      = excluded.total_input_tokens,
115→        total_output_tokens     = excluded.total_output_tokens,
116→        cache_creation_tokens   = excluded.cache_creation_tokens,
117→        cache_read_tokens       = excluded.cache_read_tokens,
118→        estimated_cost_usd      = excluded.estimated_cost_usd,
119→        models_used             = excluded.models_used,
120→        primary_model           = excluded.primary_model,
121→        usage_source            = excluded.usage_source,
122→        synced_at               = datetime('now')
123→    `);
124→  }
125→
126→  if (!_stmtInsertMessage) {
127→    _stmtInsertMessage = db.prepare(`
128→      INSERT OR IGNORE INTO messages (
129→        id, session_id, type, content, thinking,
130→        tool_calls, tool_results, usage, timestamp, parent_id
131→      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
132→    `);
133→  }
134→
135→  if (!_stmtUpsertUsageStatsIncrement) {
136→    _stmtUpsertUsageStatsIncrement = db.prepare(`
137→      INSERT INTO usage_stats (id, total_input_tokens, total_output_tokens, cache_creation_tokens, cache_read_tokens, estimated_cost_usd, sessions_with_usage, last_updated_at)
138→      VALUES (1, ?, ?, ?, ?, ?, 1, datetime('now'))
139→      ON CONFLICT(id) DO UPDATE SET
140→        total_input_tokens    = total_input_tokens + excluded.total_input_tokens,
141→        total_output_tokens   = total_output_tokens + excluded.total_output_tokens,
142→        cache_creation_tokens = cache_creation_tokens + excluded.cache_creation_tokens,
143→        cache_read_tokens     = cache_read_tokens + excluded.cache_read_tokens,
144→        estimated_cost_usd    = estimated_cost_usd + excluded.estimated_cost_usd,
145→        sessions_with_usage   = sessions_with_usage + 1,
146→        last_updated_at       = datetime('now')
147→    `);
148→  }
149→
150→  return {
151→    upsertProjectBase: _stmtUpsertProjectBase,
152→    updateProjectWithUsage: _stmtUpdateProjectWithUsage,
153→    updateProjectCountOnly: _stmtUpdateProjectCountOnly,
154→    upsertSession: _stmtUpsertSession,
155→    insertMessage: _stmtInsertMessage,
156→    upsertUsageStatsIncrement: _stmtUpsertUsageStatsIncrement,
157→  };
158→}
159→
160→/**
161→ * Upsert project record and insert session + messages.
162→ * Replaces firebase/client.ts uploadSession() + uploadMessages().
163→ *
164→ * isForce: when true (--force sync), usage stats on the project are NOT
165→ * incrementally added — they'll be recalculated via recalculateUsageStats().
166→ */
167→export function insertSessionWithProject(session: ParsedSession, isForce = false): void {
168→  const db = getDb();
169→  const { projectId, source: projectIdSource, gitRemoteUrl } = generateStableProjectId(session.projectPath);
170→  const deviceInfo = getDeviceInfo();
171→
172→  const isNew = !sessionExists(session.id);
173→
174→  const tx = db.transaction(() => {
175→    upsertProject(projectId, session, projectIdSource, gitRemoteUrl, isNew, isForce);
176→    upsertSession(session, projectId, gitRemoteUrl, deviceInfo);
177→    if (isNew) {
178→      updateGlobalUsageStats(session, isForce);
179→    }
180→  });
181→
182→  tx();
183→}
184→
185→
186→function upsertProject(
187→  projectId: string,
188→  session: ParsedSession,
189→  projectIdSource: string,
190→  gitRemoteUrl: string | null,
191→  isNewSession: boolean,
192→  isForce: boolean,
193→): void {
194→  const stmts = getStmts();
195→
196→  // Insert project if it doesn't exist
197→  stmts.upsertProjectBase.run(
198→    projectId,
199→    session.projectName,
200→    session.projectPath,
201→    gitRemoteUrl,
202→    projectIdSource,
203→    session.endedAt.toISOString(),
204→  );
205→
206→  // Increment session count and usage only for genuinely new sessions
207→  if (isNewSession && !isForce && session.usage) {
208→    stmts.updateProjectWithUsage.run(
209→      session.usage.totalInputTokens,
210→      session.usage.totalOutputTokens,
211→      session.usage.cacheCreationTokens,
212→      session.usage.cacheReadTokens,
213→      session.usage.estimatedCostUsd,
214→      projectId,
215→    );
216→  } else if (isNewSession) {
217→    stmts.updateProjectCountOnly.run(projectId);
218→  }
219→}
220→
221→function upsertSession(
222→  session: ParsedSession,
223→  projectId: string,
224→  gitRemoteUrl: string | null,
225→  deviceInfo: { deviceId: string; hostname: string; platform: string },
226→): void {
227→  const stmts = getStmts();
228→  stmts.upsertSession.run(
229→    session.id,
230→    projectId,
231→    session.projectName,
232→    session.projectPath,
233→    gitRemoteUrl,
234→    session.summary,
235→    session.generatedTitle,
236→    session.titleSource,
237→    session.sessionCharacter,
238→    session.startedAt.toISOString(),
239→    session.endedAt.toISOString(),
240→    session.messageCount,
241→    session.userMessageCount,
242→    session.assistantMessageCount,
243→    session.toolCallCount,
244→    session.gitBranch,
245→    session.claudeVersion,
246→    session.sourceTool ?? 'claude-code',
247→    deviceInfo.deviceId,
248→    deviceInfo.hostname,
249→    deviceInfo.platform,
250→    session.usage?.totalInputTokens ?? null,
251→    session.usage?.totalOutputTokens ?? null,
252→    session.usage?.cacheCreationTokens ?? null,
253→    session.usage?.cacheReadTokens ?? null,
254→    session.usage?.estimatedCostUsd ?? null,
255→    session.usage?.modelsUsed ? JSON.stringify(session.usage.modelsUsed) : null,
256→    session.usage?.primaryModel ?? null,
257→    session.usage?.usageSource ?? null,
258→  );
259→}
260→
261→/**
262→ * Insert messages for a session.
263→ * Replaces firebase/client.ts uploadMessages().
264→ */
265→export function insertMessages(session: ParsedSession): void {
266→  if (session.messages.length === 0) return;
267→
268→  const db = getDb();
269→  const stmts = getStmts();
270→
271→  const tx = db.transaction((messages: ParsedMessage[]) => {
272→    for (const msg of messages) {
273→      stmts.insertMessage.run(
274→        msg.id,
275→        msg.sessionId,
276→        msg.type,
277→        truncate(msg.content, CONTENT_MAX),
278→        msg.thinking ? truncate(msg.thinking, THINKING_MAX) : null,
279→        msg.toolCalls.length > 0
280→          ? JSON.stringify(msg.toolCalls.map(tc => ({
281→              id: tc.id,
282→              name: tc.name,
283→              input: JSON.stringify(tc.input).slice(0, TOOL_INPUT_MAX),
284→            })))
285→          : null,
286→        msg.toolResults.length > 0
287→          ? JSON.stringify(msg.toolResults.map(tr => ({
288→              toolUseId: tr.toolUseId,
289→              output: truncate(tr.output, TOOL_RESULT_MAX),
290→            })))
291→          : null,
292→        msg.usage ? JSON.stringify(msg.usage) : null,
293→        msg.timestamp.toISOString(),
294→        msg.parentId,
295→      );
296→    }
297→  });
298→
299→  tx(session.messages);
300→}
301→
302→/**
303→ * After a --force sync, recalculate usage_stats singleton from all sessions.
304→ * Also recalculates per-project usage totals.
305→ */
306→export function recalculateUsageStats(): { sessionsWithUsage: number; totalTokens: number; estimatedCostUsd: number } {
307→  const db = getDb();
308→
309→  const tx = db.transaction(() => {
310→    // Aggregate global stats from all sessions that have usage data
311→    const global = db.prepare(`
312→      SELECT
313→        COUNT(*)                       AS sessions_with_usage,
314→        SUM(total_input_tokens)        AS total_input,
315→        SUM(total_output_tokens)       AS total_output,
316→        SUM(cache_creation_tokens)     AS cache_creation,
317→        SUM(cache_read_tokens)         AS cache_read,
318→        SUM(estimated_cost_usd)        AS total_cost
319→      FROM sessions
320→      WHERE usage_source IS NOT NULL
321→    `).get() as {
322→      sessions_with_usage: number;
323→      total_input: number | null;
324→      total_output: number | null;
325→      cache_creation: number | null;
326→      cache_read: number | null;
327→      total_cost: number | null;
328→    };
329→
330→    // Upsert the singleton usage_stats row
331→    db.prepare(`
332→      INSERT INTO usage_stats (id, total_input_tokens, total_output_tokens, cache_creation_tokens, cache_read_tokens, estimated_cost_usd, sessions_with_usage, last_updated_at)
333→      VALUES (1, ?, ?, ?, ?, ?, ?, datetime('now'))
334→      ON CONFLICT(id) DO UPDATE SET
335→        total_input_tokens    = excluded.total_input_tokens,
336→        total_output_tokens   = excluded.total_output_tokens,
337→        cache_creation_tokens = excluded.cache_creation_tokens,
338→        cache_read_tokens     = excluded.cache_read_tokens,
339→        estimated_cost_usd    = excluded.estimated_cost_usd,
340→        sessions_with_usage   = excluded.sessions_with_usage,
341→        last_updated_at       = excluded.last_updated_at
342→    `).run(
343→      global.total_input ?? 0,
344→      global.total_output ?? 0,
345→      global.cache_creation ?? 0,
346→      global.cache_read ?? 0,
347→      global.total_cost ?? 0,
348→      global.sessions_with_usage ?? 0,
349→    );
350→
351→    // Recalculate per-project usage totals
352→    const perProject = db.prepare(`
353→      SELECT
354→        project_id,
355→        COUNT(*)                   AS session_count,
356→        SUM(total_input_tokens)    AS total_input,
357→        SUM(total_output_tokens)   AS total_output,
358→        SUM(cache_creation_tokens) AS cache_creation,
359→        SUM(cache_read_tokens)     AS cache_read,
360→        SUM(estimated_cost_usd)    AS total_cost,
361→        MAX(ended_at)              AS last_activity
362→      FROM sessions
363→      GROUP BY project_id
364→    `).all() as Array<{
365→      project_id: string;
366→      session_count: number;
367→      total_input: number | null;
368→      total_output: number | null;
369→      cache_creation: number | null;
370→      cache_read: number | null;
371→      total_cost: number | null;
372→      last_activity: string;
373→    }>;
374→
375→    const updateProject = db.prepare(`
376→      UPDATE projects SET
377→        session_count         = ?,
378→        total_input_tokens    = ?,
379→        total_output_tokens   = ?,
380→        cache_creation_tokens = ?,
381→        cache_read_tokens     = ?,
382→        estimated_cost_usd    = ?,
383→        last_activity         = ?,
384→        updated_at            = datetime('now')
385→      WHERE id = ?
386→    `);
387→
388→    for (const row of perProject) {
389→      updateProject.run(
390→        row.session_count,
391→        row.total_input ?? 0,
392→        row.total_output ?? 0,
393→        row.cache_creation ?? 0,
394→        row.cache_read ?? 0,
395→        row.total_cost ?? 0,
396→        row.last_activity,
397→        row.project_id,
398→      );
399→    }
400→
401→    return global;
402→  });
403→
404→  const result = tx() as {
405→    sessions_with_usage: number;
406→    total_input: number | null;
407→    total_output: number | null;
408→    cache_creation: number | null;
409→    cache_read: number | null;
410→    total_cost: number | null;
411→  };
412→
413→  const totalTokens = (result.total_input ?? 0) + (result.total_output ?? 0)
414→    + (result.cache_creation ?? 0) + (result.cache_read ?? 0);
415→
416→  return {
417→    sessionsWithUsage: result.sessions_with_usage ?? 0,
418→    totalTokens,
419→    estimatedCostUsd: result.total_cost ?? 0,
420→  };
421→}
422→
423→function updateGlobalUsageStats(session: ParsedSession, isForce: boolean): void {
424→  if (isForce || !session.usage) return;
425→
426→  const stmts = getStmts();
427→  stmts.upsertUsageStatsIncrement.run(
428→    session.usage.totalInputTokens,
429→    session.usage.totalOutputTokens,
430→    session.usage.cacheCreationTokens,
431→    session.usage.cacheReadTokens,
432→    session.usage.estimatedCostUsd,
433→  );
434→}
