  1→import { serve } from '@hono/node-server';
  2→import { serveStatic } from '@hono/node-server/serve-static';
  3→import { Hono } from 'hono';
  4→import { existsSync, readFileSync } from 'fs';
  5→import { relative, join } from 'path';
  6→import { openUrl } from '@code-insights/cli/utils/browser';
  7→import projectsRouter from './routes/projects.js';
  8→import sessionsRouter from './routes/sessions.js';
  9→import messagesRouter from './routes/messages.js';
 10→import insightsRouter from './routes/insights.js';
 11→import analysisRouter from './routes/analysis.js';
 12→import analyticsRouter from './routes/analytics.js';
 13→import configRouter from './routes/config.js';
 14→import exportRouter from './routes/export.js';
 15→
 16→export interface ServerOptions {
 17→  port: number;
 18→  // Absolute path to the dashboard/dist directory
 19→  staticDir: string;
 20→  openBrowser: boolean;
 21→}
 22→
 23→/**
 24→ * Start the Code Insights local dashboard server.
 25→ * Serves the Hono API and the pre-built Vite SPA from staticDir.
 26→ * Called by the CLI `dashboard` command.
 27→ */
 28→export async function startServer(options: ServerOptions): Promise<void> {
 29→  const { port, staticDir, openBrowser } = options;
 30→
 31→  const app = new Hono();
 32→
 33→  // Global error handler — prevents stack trace leakage to clients.
 34→  // Detects malformed JSON bodies (SyntaxError) and returns 400 instead of 500.
 35→  app.onError((err, c) => {
 36→    if (err instanceof SyntaxError && err.message.includes('JSON')) {
 37→      return c.json({ error: 'Invalid JSON in request body' }, 400);
 38→    }
 39→    console.error(err);
 40→    return c.json({ error: 'Internal server error' }, 500);
 41→  });
 42→
 43→  // API routes — all under /api
 44→  app.route('/api/projects', projectsRouter);
 45→  app.route('/api/sessions', sessionsRouter);
 46→  app.route('/api/messages', messagesRouter);
 47→  app.route('/api/insights', insightsRouter);
 48→  app.route('/api/analysis', analysisRouter);
 49→  app.route('/api/analytics', analyticsRouter);
 50→  app.route('/api/config', configRouter);
 51→  app.route('/api/export', exportRouter);
 52→
 53→  // Health check
 54→  app.get('/api/health', (c) => c.json({ ok: true, version: '0.1.0' }));
 55→
 56→  // API 404 catch-all — must come AFTER all /api sub-routers and BEFORE static serving.
 57→  // Without this, unmatched /api/* routes fall through to the SPA fallback and return
 58→  // index.html as 200, which breaks API clients expecting JSON errors.
 59→  app.all('/api/*', (c) => c.json({ error: 'Not found' }, 404));
 60→
 61→  // Static file serving — only if the dashboard has been built.
 62→  // serveStatic requires a path relative to process.cwd(), not an absolute path.
 63→  if (existsSync(staticDir)) {
 64→    const relativeStaticDir = relative(process.cwd(), staticDir);
 65→    app.use('/*', serveStatic({ root: relativeStaticDir }));
 66→
 67→    // Cache index.html at startup — avoids a readFileSync on every SPA navigation
 68→    // request, which would be a pointless disk read for a file that never changes
 69→    // while the server is running.
 70→    const indexPath = join(staticDir, 'index.html');
 71→    const indexHtml = existsSync(indexPath) ? readFileSync(indexPath, 'utf-8') : null;
 72→
 73→    // SPA fallback: any non-API route not matched by serveStatic serves index.html
 74→    // so react-router can handle client-side routing.
 75→    app.get('*', (c) => {
 76→      if (indexHtml) return c.html(indexHtml);
 77→      return c.text('Dashboard not found. Run pnpm build first.', 404);
 78→    });
 79→  } else {
 80→    // Dashboard not built — serve a helpful message
 81→    app.get('*', (c) =>
 82→      c.html(`
 83→        <html><body style="font-family:monospace;padding:2rem">
 84→          <h2>Code Insights Dashboard</h2>
 85→          <p>The dashboard has not been built yet.</p>
 86→          <pre>pnpm install &amp;&amp; pnpm build</pre>
 87→          <p>Then restart the server.</p>
 88→        </body></html>
 89→      `),
 90→    );
 91→  }
 92→
 93→  // Graceful shutdown: just call process.exit(0).
 94→  // The process 'exit' handler in cli/src/db/client.ts already calls closeDb()
 95→  // which runs WAL checkpoint. Calling closeDb() here would double-close.
 96→  const shutdown = () => {
 97→    process.exit(0);
 98→  };
 99→  process.on('SIGINT', shutdown);
100→  process.on('SIGTERM', shutdown);
101→
102→  serve({ fetch: app.fetch, port }, (info) => {
103→    const url = `http://localhost:${info.port}`;
104→    console.log(`  Code Insights dashboard running at ${url}`);
105→    if (openBrowser) {
106→      openUrl(url);
107→    }
108→  });
109→}
