  1→// ──────────────────────────────────────────────────────
  2→// Stats command — Foundation types
  3→// ──────────────────────────────────────────────────────
  4→
  5→/** Time period for filtering sessions */
  6→export type Period = '7d' | '30d' | '90d' | 'all';
  7→
  8→/** Options passed to data source query methods */
  9→export interface SessionQueryOptions {
 10→  periodStart?: Date;
 11→  projectId?: string;
 12→  sourceTool?: string;
 13→}
 14→
 15→/**
 16→ * Universal session representation.
 17→ *
 18→ * Both Firestore and local data sources produce this shape.
 19→ * Required fields are guaranteed; optional fields depend on
 20→ * whether usage/cost data was captured during the session.
 21→ */
 22→export interface SessionRow {
 23→  // identity
 24→  id: string;
 25→  projectId: string;
 26→  projectName: string;
 27→
 28→  // timing
 29→  startedAt: Date;
 30→  endedAt: Date;
 31→
 32→  // counts
 33→  messageCount: number;
 34→  userMessageCount: number;
 35→  assistantMessageCount: number;
 36→  toolCallCount: number;
 37→
 38→  // cost / usage (optional — only present when usage data was captured)
 39→  estimatedCostUsd?: number;
 40→  totalInputTokens?: number;
 41→  totalOutputTokens?: number;
 42→  cacheCreationTokens?: number;
 43→  cacheReadTokens?: number;
 44→
 45→  // metadata (optional)
 46→  primaryModel?: string;
 47→  modelsUsed?: string[];
 48→  generatedTitle?: string;
 49→  customTitle?: string;
 50→  summary?: string;
 51→  sessionCharacter?: string;
 52→  // Required: SQLite schema has source_tool NOT NULL DEFAULT 'claude-code'
 53→  sourceTool: string;
 54→  usageSource?: string;
 55→}
 56→
 57→/** Resolved project identity */
 58→export interface ProjectResolution {
 59→  projectId: string;
 60→  projectName: string;
 61→}
 62→
 63→/** Result of a data source prepare step */
 64→export interface PrepareResult {
 65→  message: string;
 66→  dataChanged: boolean;
 67→}
 68→
 69→/** Aggregated usage statistics document */
 70→export interface UsageStatsDoc {
 71→  totalInputTokens: number;
 72→  totalOutputTokens: number;
 73→  cacheCreationTokens: number;
 74→  cacheReadTokens: number;
 75→  estimatedCostUsd: number;
 76→  sessionsWithUsage: number;
 77→  lastUpdatedAt: Date;
 78→}
 79→
 80→/**
 81→ * CLI flags for the stats command.
 82→ *
 83→ * Defined here (not in shared.ts) to avoid circular imports —
 84→ * shared.ts re-exports this type.
 85→ */
 86→export interface StatsFlags {
 87→  period: Period;
 88→  project?: string;
 89→  source?: string;
 90→  noSync: boolean;
 91→}
 92→
 93→/**
 94→ * Contract that every data source must implement.
 95→ *
 96→ * Both FirestoreDataSource and LocalDataSource satisfy this
 97→ * interface, allowing the stats commands to be data-source agnostic.
 98→ */
 99→export interface StatsDataSource {
100→  readonly name: string;
101→  getSessions(opts: SessionQueryOptions): Promise<SessionRow[]>;
102→  getUsageStats(): Promise<UsageStatsDoc | null>;
103→  resolveProjectId(name: string): Promise<ProjectResolution>;
104→  getLastSession(opts?: Pick<SessionQueryOptions, 'sourceTool' | 'projectId'>): Promise<SessionRow | null>;
105→  prepare(flags: StatsFlags): Promise<PrepareResult>;
106→}
107→
