  8→/**
  9→ * OpenAI Codex CLI session provider.
 10→ * Discovers and parses rollout JSONL files from ~/.codex/sessions/
 11→ */
 12→export class CodexProvider implements SessionProvider {
 13→  getProviderName(): string {
 14→    return 'codex-cli';
 15→  }
 16→
 17→  async discover(options?: { projectFilter?: string }): Promise<string[]> {
 18→    const codexHome = getCodexHome();
 19→    if (!codexHome) return [];
 20→
 21→    const files: string[] = [];
 22→
 23→    // Walk sessions/ and archived_sessions/ directories
 24→    for (const subdir of ['sessions', 'archived_sessions']) {
 25→      const sessionsDir = path.join(codexHome, subdir);
 26→      if (!fs.existsSync(sessionsDir)) continue;
 27→      collectRolloutFiles(sessionsDir, files);
 28→    }
 29→
 30→    // Apply project filter if specified (filter by cwd from session_meta)
 31→    if (options?.projectFilter) {
 32→      return filterByProject(files, options.projectFilter);
 33→    }
 34→
 35→    return files;
 36→  }
 37→
 38→  async parse(filePath: string): Promise<ParsedSession | null> {
 39→    return parseCodexSession(filePath);
 40→  }
 41→}
 42→
 43→// ---------------------------------------------------------------------------
 44→// Discovery helpers
 45→// ---------------------------------------------------------------------------
 46→
 47→function getCodexHome(): string | null {
 48→  const envHome = process.env.CODEX_HOME;
 49→  if (envHome && fs.existsSync(envHome)) return envHome;
 50→
 51→  const home = os.homedir();
 52→  const defaultDir = path.join(home, '.codex');
 53→  return fs.existsSync(defaultDir) ? defaultDir : null;
 54→}
 55→
 56→/**
 57→ * Recursively collect rollout-*.jsonl files from date-organized directories.
 58→ * Structure: sessions/YYYY/MM/DD/rollout-<timestamp>-<uuid>.jsonl
 59→ */
 60→function collectRolloutFiles(dir: string, files: string[]): void {
 61→  const entries = fs.readdirSync(dir, { withFileTypes: true });
 62→  for (const entry of entries) {
 63→    const fullPath = path.join(dir, entry.name);
 64→    if (entry.isDirectory()) {
 65→      collectRolloutFiles(fullPath, files);
 66→    } else if (entry.name.startsWith('rollout-') && entry.name.endsWith('.jsonl')) {
 67→      files.push(fullPath);
 68→    }
 69→  }
 70→}
 71→
 72→/**
 73→ * Quick-filter by project: read only the first line (session_meta) to get cwd.
 74→ */
 75→function filterByProject(files: string[], projectFilter: string): string[] {
 76→  const filtered: string[] = [];
 77→  const lowerFilter = projectFilter.toLowerCase();
 78→
 79→  for (const filePath of files) {
 80→    try {
 81→      const fd = fs.openSync(filePath, 'r');
 82→      const buf = Buffer.alloc(2048);
 83→      const bytesRead = fs.readSync(fd, buf, 0, 2048, 0);
 84→      fs.closeSync(fd);
 85→
 86→      const firstLine = buf.toString('utf-8', 0, bytesRead).split('\n')[0];
 87→      const meta = JSON.parse(firstLine);
 88→
 89→      // session_meta has cwd field
 90→      const cwd = meta.cwd || meta.payload?.cwd || '';
 91→      if (cwd.toLowerCase().includes(lowerFilter)) {
 92→        filtered.push(filePath);
 93→      }
 94→    } catch {
 95→      // Include files we can't quick-check
 96→      filtered.push(filePath);
 97→    }
 98→  }
 99→
100→  return filtered;
101→}
