150→  cached_input_tokens?: number;
151→  output_tokens?: number;
152→  reasoning?: number;
153→}
154→
155→// ---------------------------------------------------------------------------
156→// Parser
157→// ---------------------------------------------------------------------------
158→
159→function parseCodexSession(filePath: string): ParsedSession | null {
160→  try {
161→    const content = fs.readFileSync(filePath, 'utf-8');
162→    const lines = content.split('\n').filter(line => line.trim());
163→    if (lines.length === 0) return null;
164→
165→    // Parse first line — session metadata
166→    const meta = parseSessionMeta(lines[0]);
167→    if (!meta) return null;
168→
169→    const sessionId = `codex:${meta.id}`;
170→
171→    // Parse remaining lines — events
172→    const messages: ParsedMessage[] = [];
173→    const usageEntries: CodexUsage[] = [];
174→    let model = meta.model || '';
175→    let lastTimestamp = new Date(meta.timestamp);
176→
177→    // Accumulator for current assistant turn
178→    let currentAssistantText = '';
179→    let currentToolCalls: ToolCall[] = [];
180→    let currentToolResults: ToolResult[] = [];
181→    let currentThinking: string | null = null;
182→    let turnUsage: CodexUsage | null = null;
183→    let toolCounter = 0;
184→
185→    function flushAssistantTurn(): void {
186→      const text = currentAssistantText.trim();
187→      if (!text && currentToolCalls.length === 0) return;
188→
189→      const msgUsage: MessageUsage | null = turnUsage ? {
190→        inputTokens: turnUsage.input_tokens || 0,
191→        outputTokens: turnUsage.output_tokens || 0,
192→        cacheCreationTokens: 0,
193→        cacheReadTokens: turnUsage.cached_input_tokens || 0,
194→        model: model || 'unknown',
195→        estimatedCostUsd: 0,
196→      } : null;
197→
198→      messages.push({
199→        id: `codex-assistant-${messages.length}`,
200→        sessionId: sessionId,
201→        type: 'assistant',
202→        content: text.slice(0, 10000),
203→        thinking: currentThinking,
204→        toolCalls: [...currentToolCalls],
205→        toolResults: [...currentToolResults],
206→        usage: msgUsage,
207→        timestamp: lastTimestamp,
208→        parentId: null,
209→      });
210→
211→      // Reset accumulators
212→      currentAssistantText = '';
213→      currentToolCalls = [];
214→      currentToolResults = [];
215→      currentThinking = null;
216→      turnUsage = null;
217→    }
218→
219→    for (let i = 1; i < lines.length; i++) {
220→      const line = lines[i];
221→      let event: CodexRolloutLine;
222→      try {
223→        event = JSON.parse(line) as CodexRolloutLine;
224→      } catch {
225→        continue;
226→      }
227→
228→      // Unwrap RolloutLine envelope if present
229→      const eventType = event.type;
230→      const payload = (event.payload || event) as Record<string, unknown>;
231→
232→      // Handle different event types
233→      const innerType = (payload.type as string) || eventType;
234→
235→      switch (innerType) {
236→        case 'user_message':
237→        case 'userMessage': {
238→          // Flush any pending assistant turn
239→          flushAssistantTurn();
240→
241→          const userContent = extractUserContent(payload);
242→          if (userContent) {
243→            messages.push({
244→              id: (payload.id as string) || `codex-user-${messages.length}`,
245→              sessionId: sessionId,
246→              type: 'user',
247→              content: userContent.slice(0, 10000),
248→              thinking: null,
249→              toolCalls: [],
250→              toolResults: [],
251→              usage: null,
252→              timestamp: parseTimestamp(payload) || lastTimestamp,
253→              parentId: null,
254→            });
255→            lastTimestamp = messages[messages.length - 1].timestamp;
256→          }
257→          break;
258→        }
259→
260→        case 'agent_message':
261→        case 'agentMessage':
262→        case 'item.completed': {
263→          const item = (payload.item || payload) as CodexItem;
264→          const itemType = item.type || innerType;
265→
266→          if (itemType === 'agent_message' || itemType === 'agentMessage') {
267→            currentAssistantText += (item.text || (payload.text as string) || '') + '\n';
268→          } else if (itemType === 'command_execution' || itemType === 'commandExecution') {
269→            toolCounter++;
270→            currentToolCalls.push({
271→              id: item.id || `codex-tool-${toolCounter}`,
272→              name: 'shell',
273→              input: { command: item.command || '', cwd: item.cwd || '' },
274→            });
275→            if (item.aggregatedOutput) {
276→              currentToolResults.push({
277→                toolUseId: item.id || `codex-tool-${toolCounter}`,
278→                output: (item.aggregatedOutput || '').slice(0, 1000),
279→              });
280→            }
281→          } else if (itemType === 'file_change' || itemType === 'fileChange') {
282→            if (item.changes) {
283→              for (const change of item.changes) {
284→                toolCounter++;
285→                currentToolCalls.push({
286→                  id: `codex-file-${toolCounter}`,
287→                  name: 'apply_patch',
288→                  input: { path: change.path, kind: change.kind },
289→                });
290→                if (change.diff) {
291→                  currentToolResults.push({
292→                    toolUseId: `codex-file-${toolCounter}`,
293→                    output: change.diff.slice(0, 1000),
294→                  });
295→                }
296→              }
297→            }
298→          } else if (itemType === 'mcp_tool_call' || itemType === 'mcpToolCall') {
299→            toolCounter++;
300→            currentToolCalls.push({
301→              id: item.id || `codex-mcp-${toolCounter}`,
302→              name: item.tool || 'mcp_tool',
303→              input: item.arguments || {},
304→            });
305→            if (item.result) {
306→              currentToolResults.push({
307→                toolUseId: item.id || `codex-mcp-${toolCounter}`,
308→                output: (item.result || '').slice(0, 1000),
309→              });
310→            }
311→          } else if (itemType === 'reasoning') {
312→            currentThinking = item.summary || (item.text as unknown as string) || null;
313→          }
314→          break;
315→        }
316→
317→        case 'turn.completed': {
318→          const usage = (payload.usage || payload) as CodexUsage;
319→          if (usage.input_tokens) {
320→            turnUsage = usage;
321→            usageEntries.push(usage);
322→          }
323→          if ((payload as Record<string, unknown>).model) {
324→            model = (payload as Record<string, unknown>).model as string;
325→          }
326→
327→          // Flush assistant turn at turn boundary
328→          flushAssistantTurn();
329→          break;
330→        }
331→
332→        case 'turn.started':
333→        case 'thread.started':
334→        case 'session_meta':
335→          // Lifecycle events — skip
336→          break;
337→      }
338→    }
339→
340→    // Flush any remaining assistant content
341→    flushAssistantTurn();
342→
343→    if (messages.length === 0) return null;
344→
345→    // Build session
346→    const userMessages = messages.filter(m => m.type === 'user');
347→    const assistantMessages = messages.filter(m => m.type === 'assistant');
348→    const toolCallCount = messages.reduce((sum, m) => sum + m.toolCalls.length, 0);
349→
350→    const timestamps = messages.map(m => m.timestamp.getTime()).filter(t => t > 0);
351→    const startedAt = timestamps.length > 0 ? new Date(Math.min(...timestamps)) : new Date(meta.timestamp);
352→    const endedAt = timestamps.length > 0 ? new Date(Math.max(...timestamps)) : lastTimestamp;
353→
354→    // Build session usage from accumulated turn usage
355→    const totalInput = usageEntries.reduce((s, u) => s + (u.input_tokens || 0), 0);
356→    const totalOutput = usageEntries.reduce((s, u) => s + (u.output_tokens || 0), 0);
357→    const totalCached = usageEntries.reduce((s, u) => s + (u.cached_input_tokens || 0), 0);
358→
359→    const usage: SessionUsage | undefined = totalInput > 0 ? {
360→      totalInputTokens: totalInput,
361→      totalOutputTokens: totalOutput,
362→      cacheCreationTokens: 0,
363→      cacheReadTokens: totalCached,
364→      estimatedCostUsd: 0, // TODO: Codex pricing not public
365→      modelsUsed: model ? [model] : [],
366→      primaryModel: model || 'unknown',
367→      usageSource: 'jsonl',
368→    } : undefined;
369→
370→    const projectPath = meta.cwd || 'codex://unknown';
371→    const projectName = path.basename(projectPath);
372→
373→    const session: ParsedSession = {
374→      id: sessionId,
375→      projectPath,
376→      projectName,
377→      summary: null,
378→      generatedTitle: null,
379→      titleSource: null,
380→      sessionCharacter: null,
381→      startedAt,
382→      endedAt,
383→      messageCount: messages.length,
384→      userMessageCount: userMessages.length,
385→      assistantMessageCount: assistantMessages.length,
386→      toolCallCount,
387→      gitBranch: null,
388→      claudeVersion: meta.cli_version || null,
389→      sourceTool: 'codex-cli',
390→      usage,
391→      messages,
392→    };
393→
394→    // Generate title and character
395→    const titleResult = generateTitle(session);
396→    session.generatedTitle = titleResult.title;
397→    session.titleSource = titleResult.source;
398→    session.sessionCharacter = titleResult.character || detectSessionCharacter(session);
399→
400→    return session;
401→  } catch {
402→    return null;
403→  }
404→}
405→
406→// ---------------------------------------------------------------------------
407→// Parsing helpers
408→// ---------------------------------------------------------------------------
409→
410→function parseSessionMeta(line: string): CodexSessionMeta | null {
411→  try {
412→    const parsed = JSON.parse(line);
413→    // Handle RolloutLine envelope
414→    if (parsed.payload && parsed.type === 'session_meta') {
415→      return parsed.payload as CodexSessionMeta;
416→    }
417→    // Handle bare session_meta (legacy or direct)
418→    if (parsed.type === 'session_meta' || parsed.id) {
419→      return parsed as CodexSessionMeta;
420→    }
421→    return null;
422→  } catch {
423→    return null;
424→  }
425→}
426→
427→function extractUserContent(payload: Record<string, unknown>): string | null {
428→  if (typeof payload.text === 'string') return payload.text;
429→  if (typeof payload.content === 'string') return payload.content;
430→  if (Array.isArray(payload.content)) {
431→    return (payload.content as Array<Record<string, string>>)
432→      .filter(c => c.type === 'text')
433→      .map(c => c.text)
434→      .join('\n');
435→  }
436→  // Nested in item
437→  const item = payload.item as Record<string, unknown> | undefined;
438→  if (item) return extractUserContent(item);
439→  return null;
440→}
441→
442→function parseTimestamp(payload: Record<string, unknown>): Date | null {
443→  const ts = payload.timestamp || payload.createdAt;
444→  if (!ts) return null;
445→  const d = new Date(ts as string | number);
446→  return isNaN(d.getTime()) ? null : d;
447→}
