  1→import * as fs from 'fs';
  2→import * as path from 'path';
  3→import * as os from 'os';
  4→import type { SessionProvider } from './types.js';
  5→import type { ParsedSession, ParsedMessage, ToolCall, ToolResult } from '../types.js';
  6→import { generateTitle, detectSessionCharacter } from '../parser/titles.js';
  7→
  8→/**
  9→ * GitHub Copilot CLI session provider.
 10→ * Discovers and parses events.jsonl files from ~/.copilot/session-state/
 11→ */
 12→export class CopilotCliProvider implements SessionProvider {
 13→  getProviderName(): string {
 14→    return 'copilot-cli';
 15→  }
 16→
 17→  async discover(options?: { projectFilter?: string }): Promise<string[]> {
 18→    const copilotHome = getCopilotHome();
 19→    if (!copilotHome) return [];
 20→
 21→    const files: string[] = [];
 22→
 23→    // Walk session-state/ and history-session-state/ directories
 24→    for (const subdir of ['session-state', 'history-session-state']) {
 25→      const sessionsDir = path.join(copilotHome, subdir);
 26→      if (!fs.existsSync(sessionsDir)) continue;
 27→      collectEventsFiles(sessionsDir, files);
 28→    }
 29→
 30→    // Apply project filter if specified (filter by cwd from workspace.yaml)
 31→    if (options?.projectFilter) {
 32→      return filterByProject(files, options.projectFilter);
 33→    }
 34→
 35→    return files;
 36→  }
 37→
 38→  async parse(filePath: string): Promise<ParsedSession | null> {
 39→    return parseCopilotSession(filePath);
 40→  }
 41→}
 42→
 43→// ---------------------------------------------------------------------------
 44→// Discovery helpers
 45→// ---------------------------------------------------------------------------
 46→
 47→function getCopilotHome(): string | null {
 48→  const envHome = process.env.COPILOT_HOME;
 49→  if (envHome && fs.existsSync(envHome)) return envHome;
 50→
 51→  const home = os.homedir();
 52→  const defaultDir = path.join(home, '.copilot');
 53→  return fs.existsSync(defaultDir) ? defaultDir : null;
 54→}
 55→
 56→/**
 57→ * Collect events.jsonl files from session directories.
 58→ * Structure: session-state/{session-id}/events.jsonl
 59→ */
 60→function collectEventsFiles(dir: string, files: string[]): void {
 61→  let entries: fs.Dirent[];
 62→  try {
 63→    entries = fs.readdirSync(dir, { withFileTypes: true });
 64→  } catch {
 65→    return;
 66→  }
 67→
 68→  for (const entry of entries) {
 69→    if (!entry.isDirectory()) continue;
 70→    const eventsPath = path.join(dir, entry.name, 'events.jsonl');
 71→    if (fs.existsSync(eventsPath)) {
 72→      files.push(eventsPath);
 73→    }
 74→  }
 75→}
 76→
 77→/**
 78→ * Quick-filter by project: read workspace.yaml sibling for cwd.
 79→ */
 80→function filterByProject(files: string[], projectFilter: string): string[] {
 81→  const filtered: string[] = [];
 82→  const lowerFilter = projectFilter.toLowerCase();
 83→
 84→  for (const filePath of files) {
 85→    try {
 86→      const sessionDir = path.dirname(filePath);
 87→      const workspacePath = path.join(sessionDir, 'workspace.yaml');
 88→
 89→      if (fs.existsSync(workspacePath)) {
 90→        const yamlContent = fs.readFileSync(workspacePath, 'utf-8');
 91→        const meta = parseWorkspaceYaml(yamlContent);
 92→        const cwd = meta.cwd || '';
 93→        if (cwd.toLowerCase().includes(lowerFilter)) {
 94→          filtered.push(filePath);
 95→          continue;
 96→        }
 97→      }
 98→
 99→      // If no workspace.yaml or no cwd match, try reading first line of events.jsonl
100→      // for session.start event with cwd
101→      const fd = fs.openSync(filePath, 'r');
102→      const buf = Buffer.alloc(2048);
103→      const bytesRead = fs.readSync(fd, buf, 0, 2048, 0);
104→      fs.closeSync(fd);
105→
106→      const firstLine = buf.toString('utf-8', 0, bytesRead).split('\n')[0];
107→      const event = JSON.parse(firstLine);
108→      const data = event.data || event;
109→      const cwd = data.cwd || '';
110→      if (cwd.toLowerCase().includes(lowerFilter)) {
111→        filtered.push(filePath);
112→      }
113→    } catch {
114→      // Include files we can't quick-check
115→      filtered.push(filePath);
116→    }
117→  }
118→
119→  return filtered;
120→}
121→
122→// ---------------------------------------------------------------------------
123→// workspace.yaml parser (no YAML library — simple key: value)
124→// ---------------------------------------------------------------------------
125→
126→function parseWorkspaceYaml(content: string): Record<string, string> {
127→  const result: Record<string, string> = {};
128→  for (const line of content.split('\n')) {
129→    const colonIdx = line.indexOf(':');
130→    if (colonIdx === -1) continue;
131→    const key = line.slice(0, colonIdx).trim();
132→    const value = line.slice(colonIdx + 1).trim();
133→    if (key && value) result[key] = value;
134→  }
135→  return result;
136→}
137→
138→// ---------------------------------------------------------------------------
139→// Copilot event types
140→// ---------------------------------------------------------------------------
141→
142→interface CopilotEvent {
143→  type: string;
144→  data?: Record<string, unknown>;
145→  // Allow bare event format (forward compatibility)
146→  [key: string]: unknown;
147→}
148→
149→// ---------------------------------------------------------------------------
150→// Parser
151→// ---------------------------------------------------------------------------
152→
153→function parseCopilotSession(filePath: string): ParsedSession | null {
154→  try {
155→    const sessionDir = path.dirname(filePath);
156→    const sessionDirName = path.basename(sessionDir);
157→
158→    // Read workspace.yaml for metadata (if present)
159→    const workspacePath = path.join(sessionDir, 'workspace.yaml');
160→    let workspaceMeta: Record<string, string> = {};
161→    if (fs.existsSync(workspacePath)) {
162→      workspaceMeta = parseWorkspaceYaml(fs.readFileSync(workspacePath, 'utf-8'));
163→    }
164→
165→    // Read events.jsonl
166→    const content = fs.readFileSync(filePath, 'utf-8');
167→    const lines = content.split('\n').filter(line => line.trim());
168→    if (lines.length === 0) return null;
169→
170→    const sessionId = `copilot:${sessionDirName}`;
171→    let model = workspaceMeta.model || '';
172→    let cwd = workspaceMeta.cwd || '';
173→    let sessionName = workspaceMeta.name || '';
174→
175→    // Parse events
176→    const messages: ParsedMessage[] = [];
177→    let lastTimestamp = fs.statSync(filePath).mtime;
178→    let firstTimestamp: Date | null = null;
179→
180→    // Accumulator for current assistant turn
181→    let currentAssistantText = '';
182→    let currentToolCalls: ToolCall[] = [];
183→    let currentToolResults: ToolResult[] = [];
184→    let toolCounter = 0;
185→
186→    function flushAssistantTurn(): void {
187→      const text = currentAssistantText.trim();
188→      if (!text && currentToolCalls.length === 0) return;
189→
190→      messages.push({
191→        id: `copilot-assistant-${messages.length}`,
192→        sessionId: sessionId,
193→        type: 'assistant',
194→        content: text.slice(0, 10000),
195→        thinking: null,
196→        toolCalls: [...currentToolCalls],
197→        toolResults: [...currentToolResults],
198→        usage: null,
199→        timestamp: lastTimestamp,
200→        parentId: null,
201→      });
202→
203→      // Reset accumulators
204→      currentAssistantText = '';
205→      currentToolCalls = [];
206→      currentToolResults = [];
207→    }
208→
209→    for (const line of lines) {
210→      let event: CopilotEvent;
211→      try {
212→        event = JSON.parse(line) as CopilotEvent;
213→      } catch {
214→        continue;
215→      }
216→
217→      // Unwrap envelope: support both {type, data} and bare event formats
218→      const eventType = event.type;
219→      const data = (event.data || event) as Record<string, unknown>;
220→
221→      // Extract timestamp if present
222→      const ts = parseTimestamp(data);
223→      if (ts) {
224→        lastTimestamp = ts;
225→        if (!firstTimestamp) firstTimestamp = ts;
226→      }
227→
228→      switch (eventType) {
229→        case 'session.start': {
230→          // Extract session metadata
231→          if (!cwd && data.cwd) cwd = data.cwd as string;
232→          if (!model && data.model) model = data.model as string;
233→          if (!sessionName && data.name) sessionName = data.name as string;
234→          break;
235→        }
236→
237→        case 'user.message': {
238→          // Flush any pending assistant turn
239→          flushAssistantTurn();
240→
241→          const userContent = extractText(data);
242→          if (userContent) {
243→            messages.push({
244→              id: (data.id as string) || `copilot-user-${messages.length}`,
245→              sessionId: sessionId,
246→              type: 'user',
247→              content: userContent.slice(0, 10000),
248→              thinking: null,
249→              toolCalls: [],
250→              toolResults: [],
251→              usage: null,
252→              timestamp: lastTimestamp,
253→              parentId: null,
254→            });
255→          }
256→          break;
257→        }
258→
259→        case 'assistant.message': {
260→          const text = extractText(data);
261→          if (text) {
262→            currentAssistantText += text + '\n';
263→          }
264→          break;
265→        }
266→
267→        case 'assistant.message_delta': {
268→          const delta = (data.delta as string) || (data.text as string) || '';
269→          if (delta) {
270→            currentAssistantText += delta;
271→          }
272→          break;
273→        }
274→
275→        case 'tool.execution_start': {
276→          toolCounter++;
277→          const toolName = (data.toolName as string) || (data.name as string) || 'unknown_tool';
278→          const toolInput = (data.parameters || data.arguments || {}) as Record<string, unknown>;
279→          currentToolCalls.push({
280→            id: (data.id as string) || `copilot-tool-${toolCounter}`,
281→            name: toolName,
282→            input: toolInput,
283→          });
284→          break;
285→        }
286→
287→        case 'tool.execution_complete': {
288→          const toolOutput = (data.output as string) || (data.result as string) || '';
289→          const toolId = (data.id as string) || (currentToolCalls.length > 0
290→            ? currentToolCalls[currentToolCalls.length - 1].id
291→            : `copilot-tool-${toolCounter}`);
292→          if (toolOutput) {
293→            currentToolResults.push({
294→              toolUseId: toolId,
295→              output: toolOutput.slice(0, 1000),
296→            });
297→          }
298→          break;
299→        }
300→
301→        case 'subagent.started': {
302→          toolCounter++;
303→          const agentName = (data.name as string) || (data.agentName as string) || 'subagent';
304→          currentToolCalls.push({
305→            id: (data.id as string) || `copilot-subagent-${toolCounter}`,
306→            name: `subagent:${agentName}`,
307→            input: (data.parameters || data.arguments || data.input || {}) as Record<string, unknown>,
308→          });
309→          break;
310→        }
311→
312→        case 'subagent.completed': {
313→          const agentOutput = (data.output as string) || (data.result as string) || '';
314→          const agentId = (data.id as string) || (currentToolCalls.length > 0
315→            ? currentToolCalls[currentToolCalls.length - 1].id
316→            : `copilot-subagent-${toolCounter}`);
317→          if (agentOutput) {
318→            currentToolResults.push({
319→              toolUseId: agentId,
320→              output: agentOutput.slice(0, 1000),
321→            });
322→          }
323→          break;
324→        }
325→
326→        case 'session.idle': {
327→          // Turn boundary — flush accumulated assistant turn
328→          flushAssistantTurn();
329→          break;
330→        }
331→
332→        default:
333→          // Skip unknown event types gracefully
334→          break;
335→      }
336→    }
337→
338→    // Flush any remaining assistant content
339→    flushAssistantTurn();
340→
341→    if (messages.length === 0) return null;
342→
343→    // Build session
344→    const userMessages = messages.filter(m => m.type === 'user');
345→    const assistantMessages = messages.filter(m => m.type === 'assistant');
346→    const toolCallCount = messages.reduce((sum, m) => sum + m.toolCalls.length, 0);
347→
348→    const timestamps = messages.map(m => m.timestamp.getTime()).filter(t => t > 0);
349→    const startedAt = timestamps.length > 0 ? new Date(Math.min(...timestamps)) : (firstTimestamp || new Date());
350→    const endedAt = timestamps.length > 0 ? new Date(Math.max(...timestamps)) : lastTimestamp;
351→
352→    const projectPath = cwd || 'copilot://unknown';
353→    const projectName = sessionName || path.basename(projectPath);
354→
355→    const session: ParsedSession = {
356→      id: sessionId,
357→      projectPath,
358→      projectName,
359→      summary: null,
360→      generatedTitle: null,
361→      titleSource: null,
362→      sessionCharacter: null,
363→      startedAt,
364→      endedAt,
365→      messageCount: messages.length,
366→      userMessageCount: userMessages.length,
367→      assistantMessageCount: assistantMessages.length,
368→      toolCallCount,
369→      gitBranch: null,
370→      claudeVersion: model || null,
371→      sourceTool: 'copilot-cli',
372→      messages,
373→    };
374→
375→    // Generate title and character
376→    const titleResult = generateTitle(session);
377→    session.generatedTitle = titleResult.title;
378→    session.titleSource = titleResult.source;
379→    session.sessionCharacter = titleResult.character || detectSessionCharacter(session);
380→
381→    return session;
382→  } catch {
383→    return null;
384→  }
385→}
386→
387→// ---------------------------------------------------------------------------
388→// Parsing helpers
389→// ---------------------------------------------------------------------------
390→
391→function extractText(data: Record<string, unknown>): string | null {
392→  if (typeof data.text === 'string') return data.text;
393→  if (typeof data.content === 'string') return data.content;
394→  if (typeof data.message === 'string') return data.message;
395→  if (Array.isArray(data.content)) {
396→    return (data.content as Array<Record<string, string>>)
397→      .filter(c => c.type === 'text')
398→      .map(c => c.text)
399→      .join('\n');
400→  }
401→  return null;
402→}
403→
404→function parseTimestamp(data: Record<string, unknown>): Date | null {
405→  const ts = data.timestamp || data.createdAt || data.time;
406→  if (!ts) return null;
407→  const d = new Date(ts as string | number);
408→  return isNaN(d.getTime()) ? null : d;
409→}
