27→           started_at, ended_at, message_count, user_message_count,
28→           assistant_message_count, tool_call_count, git_branch,
29→           claude_version, source_tool, device_id, device_hostname,
30→           device_platform, synced_at, total_input_tokens, total_output_tokens,
31→           cache_creation_tokens, cache_read_tokens, estimated_cost_usd,
32→           models_used, primary_model, usage_source
33→    FROM sessions
34→    ${where}
35→    ORDER BY started_at DESC
36→    LIMIT ? OFFSET ?
37→  `).all(...params, parseIntParam(limit, 50), parseIntParam(offset, 0));
38→
39→  return c.json({ sessions });
