 98→/**
 99→ * Find Cursor's data directory based on the current platform.
100→ */
101→function getCursorDataDir(): string | null {
102→  const platform = process.platform;
103→  const home = os.homedir();
104→
105→  let dataDir: string;
106→  if (platform === 'darwin') {
107→    dataDir = path.join(home, 'Library', 'Application Support', 'Cursor', 'User');
108→  } else if (platform === 'linux') {
109→    dataDir = path.join(home, '.config', 'Cursor', 'User');
110→  } else if (platform === 'win32') {
111→    dataDir = path.join(process.env.APPDATA || path.join(home, 'AppData', 'Roaming'), 'Cursor', 'User');
112→  } else {
113→    return null;
114→  }
115→
116→  return fs.existsSync(dataDir) ? dataDir : null;
117→}
118→
119→/**
120→ * Resolve the project path from a workspace hash directory.
121→ * Reads workspace.json which contains the folder URI.
122→ */
123→function resolveWorkspacePath(wsDir: string): string | null {
124→  const workspaceJsonPath = path.join(wsDir, 'workspace.json');
125→  if (fs.existsSync(workspaceJsonPath)) {
126→    try {
127→      const data = JSON.parse(fs.readFileSync(workspaceJsonPath, 'utf-8'));
128→      if (data.folder) {
129→        // folder is a file:// URI like "file:///Users/name/projects/my-app"
130→        try {
131→          const url = new URL(data.folder);
132→          return url.pathname;
133→        } catch {
134→          // Not a valid URL, try using it as-is
135→          return data.folder;
136→        }
137→      }
138→    } catch {
139→      // Ignore parse errors
140→    }
141→  }
142→  return null;
143→}
144→
145→/**
146→ * Get all composer IDs from a Cursor database file.
147→ * Tries multiple storage strategies to find composer sessions.
148→ */
149→function getComposerIds(dbPath: string): string[] {
150→  let db: InstanceType<typeof Database> | null = null;
151→  try {
152→    db = new Database(dbPath, { readonly: true, fileMustExist: true });
153→
154→    const ids: string[] = [];
155→
156→    // Strategy 1: Check cursorDiskKV table for composerData entries (global DB)
157→    const hasCursorDiskKV = db.prepare(
158→      "SELECT name FROM sqlite_master WHERE type='table' AND name='cursorDiskKV'"
159→    ).get();
160→
161→    if (hasCursorDiskKV) {
162→      const rows = db.prepare(
163→        "SELECT key FROM cursorDiskKV WHERE key LIKE 'composerData:%'"
164→      ).all() as { key: string }[];
165→
166→      for (const row of rows) {
167→        const composerId = row.key.replace('composerData:', '');
168→        if (composerId) ids.push(composerId);
169→      }
170→    }
171→
172→    // Strategy 2: Check ItemTable for composer.composerData (workspace DBs)
173→    if (ids.length === 0) {
174→      const hasItemTable = db.prepare(
175→        "SELECT name FROM sqlite_master WHERE type='table' AND name='ItemTable'"
176→      ).get();
177→
178→      if (hasItemTable) {
179→        const row = db.prepare(
180→          "SELECT value FROM ItemTable WHERE key = 'composer.composerData'"
181→        ).get() as { value: string } | undefined;
182→
183→        if (row?.value) {
184→          try {
185→            const data = JSON.parse(row.value);
186→            const composers = data.allComposers || data.composers || [];
187→            for (const c of composers) {
188→              if (c.composerId) ids.push(c.composerId);
189→            }
190→          } catch {
191→            // Ignore parse errors
192→          }
193→        }
194→      }
195→    }
196→
197→    return ids;
198→  } catch {
199→    return [];
200→  } finally {
201→    db?.close();
202→  }
203→}
204→
205→/**
206→ * Parse a single Cursor composer session from a database.
207→ */
208→function parseCursorSession(dbPath: string, composerId: string): ParsedSession | null {
209→  let db: InstanceType<typeof Database> | null = null;
210→  try {
211→    db = new Database(dbPath, { readonly: true, fileMustExist: true });
212→
213→    let composerData: Record<string, unknown> | null = null;
214→
215→    // Try cursorDiskKV first (global DB)
216→    const hasCursorDiskKV = db.prepare(
217→      "SELECT name FROM sqlite_master WHERE type='table' AND name='cursorDiskKV'"
218→    ).get();
219→
220→    if (hasCursorDiskKV) {
221→      const row = db.prepare(
222→        "SELECT value FROM cursorDiskKV WHERE key = ?"
223→      ).get(`composerData:${composerId}`) as { value: string } | undefined;
224→
225→      if (row?.value) {
226→        composerData = JSON.parse(row.value) as Record<string, unknown>;
227→      }
228→    }
229→
230→    // Fallback: try ItemTable composer.composerData
231→    if (!composerData) {
232→      const hasItemTable = db.prepare(
233→        "SELECT name FROM sqlite_master WHERE type='table' AND name='ItemTable'"
234→      ).get();
235→
236→      if (hasItemTable) {
237→        const row = db.prepare(
238→          "SELECT value FROM ItemTable WHERE key = 'composer.composerData'"
239→        ).get() as { value: string } | undefined;
240→
241→        if (row?.value) {
242→          const allData = JSON.parse(row.value) as Record<string, unknown>;
243→          const composers = (allData.allComposers || allData.composers || []) as Array<Record<string, unknown>>;
244→          composerData = composers.find((c) => c.composerId === composerId) || null;
245→        }
246→      }
247→    }
248→
249→    if (!composerData) return null;
250→
251→    // Extract messages from composer data
252→    // Pass db handle for the fullConversationHeadersOnly format where
253→    // bubble content is stored in separate cursorDiskKV rows.
254→    const messages = extractMessages(composerData, composerId, db);
255→    if (messages.length === 0) return null;
256→
257→    // Resolve project path from workspace directory
258→    const wsDir = path.dirname(dbPath); // e.g., workspaceStorage/<hash>/
259→    const projectPath = resolveWorkspacePath(wsDir) || 'cursor://global';
260→    const projectName = path.basename(projectPath);
261→
262→    // Build timestamps from messages
263→    const timestamps = messages.map(m => m.timestamp.getTime()).filter(t => t > 0);
264→    let startedAt = timestamps.length > 0
265→      ? new Date(timestamps.reduce((a, b) => a < b ? a : b))
266→      : new Date();
267→    let endedAt = timestamps.length > 0
268→      ? new Date(timestamps.reduce((a, b) => a > b ? a : b))
269→      : new Date();
270→
271→    // If timestamps are missing or invalid, try composerData timestamps
272→    const createdAt = composerData.createdAt as number | undefined;
273→    const lastUpdatedAt = (composerData.lastUpdatedAt || composerData.updatedAt) as number | undefined;
274→
275→    if (createdAt && timestamps.length === 0) {
276→      startedAt = new Date(createdAt);
277→    }
278→    if (lastUpdatedAt && lastUpdatedAt > startedAt.getTime()) {
279→      endedAt = new Date(lastUpdatedAt);
280→    }
281→
282→    const userMessages = messages.filter(m => m.type === 'user');
283→    const assistantMessages = messages.filter(m => m.type === 'assistant');
284→    const toolCallCount = messages.reduce((sum, m) => sum + m.toolCalls.length, 0);
285→
286→    const session: ParsedSession = {
287→      id: `cursor:${composerId}`,
288→      projectPath,
289→      projectName,
290→      summary: (composerData.name as string) || null, // Cursor's conversation name/title
291→      generatedTitle: null,
292→      titleSource: null,
293→      sessionCharacter: null,
294→      startedAt,
295→      endedAt,
296→      messageCount: messages.length,
297→      userMessageCount: userMessages.length,
298→      assistantMessageCount: assistantMessages.length,
299→      toolCallCount,
300→      gitBranch: null, // Not available from Cursor's DB
301→      claudeVersion: null,
302→      sourceTool: 'cursor',
303→      usage: undefined, // No token data in Cursor's DB
304→      messages,
305→    };
306→
307→    // Generate title using existing title generator
308→    const titleResult = generateTitle(session);
309→    session.generatedTitle = titleResult.title;
310→    session.titleSource = titleResult.source;
311→
312→    // Detect session character
313→    session.sessionCharacter = titleResult.character || detectSessionCharacter(session);
314→
315→    return session;
316→  } catch {
317→    return null;
318→  } finally {
319→    db?.close();
320→  }
321→}
322→
323→// Keys Cursor has used across versions to store the message array.
324→// Order matters: check the most common/modern formats first.
325→const CURSOR_MESSAGE_ARRAY_KEYS = [
326→  'conversation',    // Observed in Cursor ≤0.42 cursorDiskKV entries
327→  'messages',        // Earlier workspace DB format
328→  'bubbles',         // Observed in some Cursor 0.43+ cursorDiskKV entries
329→  'turns',           // Seen in experimental Cursor builds
330→  'history',         // Alternate key used in some Cursor forks
331→  'richConversation',// Rich-text variant with full markdown blocks
332→  'thread',          // Used in agent-mode sessions
333→] as const;
334→
335→/**
336→ * Find the message array in a composerData blob, trying all known key names.
337→ * Returns [array, keyUsed] so callers can log which key worked.
338→ * Returns [[], null] when no recognised key has a non-empty array.
339→ */
340→function findMessageArray(composerData: Record<string, unknown>): [Array<Record<string, unknown>>, string | null] {
341→  for (const key of CURSOR_MESSAGE_ARRAY_KEYS) {
342→    const value = composerData[key];
343→    if (Array.isArray(value) && value.length > 0) {
344→      return [value as Array<Record<string, unknown>>, key];
345→    }
346→  }
347→  return [[], null];
348→}
349→
350→/**
351→ * Extract parsed messages from Cursor composer data.
352→ *
353→ * Handles two storage formats:
354→ * 1. Inline: composerData has a `conversation` (or `messages`, etc.) array with full bubble content.
355→ * 2. Headers-only (Cursor v3+/v6): composerData has `fullConversationHeadersOnly` with bubble IDs
356→ *    and types only. Full bubble content is stored in separate `bubbleId:<composerId>:<bubbleId>`
357→ *    rows in the same cursorDiskKV table.
358→ */
359→function extractMessages(
360→  composerData: Record<string, unknown>,
361→  sessionId: string,
362→  db: InstanceType<typeof Database> | null,
363→): ParsedMessage[] {
364→  const messages: ParsedMessage[] = [];
365→
366→  // Strategy 1: Try fullConversationHeadersOnly (newer Cursor format, ~72% of sessions)
367→  const headers = composerData.fullConversationHeadersOnly;
368→  if (Array.isArray(headers) && headers.length > 0 && db) {
369→    const conversation = loadBubblesFromHeaders(
370→      headers as Array<{ bubbleId: string; type: number }>,
371→      sessionId,
372→      db,
373→    );
374→    if (conversation.length > 0) {
375→      return parseBubbles(conversation, sessionId);
376→    }
377→    // If all bubble lookups failed, fall through to inline check
378→  }
379→
380→  // Strategy 2: Try inline message arrays (older Cursor format)
381→  const [conversation, keyUsed] = findMessageArray(composerData);
382→
383→  if (conversation.length === 0) {
384→    // No messages found — log top-level keys to help diagnose future Cursor format changes.
385→    // Only log when the composerData has keys but none match our known formats
386→    // (empty objects = legitimately empty sessions, not a format issue).
387→    const topLevelKeys = Object.keys(composerData);
388→    const knownKeys = new Set<string>([...CURSOR_MESSAGE_ARRAY_KEYS, 'fullConversationHeadersOnly']);
389→    const hasUnknownArrayKeys = topLevelKeys.some(
390→      k => !knownKeys.has(k) && Array.isArray(composerData[k])
391→    );
392→    if (topLevelKeys.length > 0 && hasUnknownArrayKeys) {
393→      if (isVerbose()) {
394→        process.stderr.write(
395→          `[code-insights] cursor: session ${sessionId} — unrecognised composerData structure. ` +
396→          `Top-level keys: [${topLevelKeys.join(', ')}]\n`
397→        );
398→      }
399→    }
400→    return messages;
401→  }
402→
403→  // Log which key was used when it's not the primary expected key — helps track format drift
404→  if (keyUsed && keyUsed !== 'conversation') {
405→    if (isVerbose()) {
406→      process.stderr.write(
407→        `[code-insights] cursor: session ${sessionId} — messages found under key "${keyUsed}"\n`
408→      );
409→    }
410→  }
411→
412→  return parseBubbles(conversation, sessionId);
413→}
414→
415→/**
416→ * Load full bubble data from individual cursorDiskKV rows.
417→ * Each bubble is stored at key `bubbleId:<composerId>:<bubbleId>`.
418→ */
419→function loadBubblesFromHeaders(
420→  headers: Array<{ bubbleId: string; type: number }>,
421→  composerId: string,
422→  db: InstanceType<typeof Database>,
423→): Array<Record<string, unknown>> {
424→  const bubbles: Array<Record<string, unknown>> = [];
425→  const stmt = db.prepare("SELECT value FROM cursorDiskKV WHERE key = ?");
426→
427→  for (const header of headers) {
428→    if (!header.bubbleId) continue;
429→    try {
430→      const row = stmt.get(`bubbleId:${composerId}:${header.bubbleId}`) as { value: string } | undefined;
431→      if (row?.value) {
432→        const bubble = JSON.parse(row.value) as Record<string, unknown>;
433→        bubbles.push(bubble);
434→      }
435→    } catch {
436→      // Individual bubble parse failure — skip it, keep loading others
437→    }
438→  }
439→
440→  return bubbles;
441→}
442→
443→/**
444→ * Parse an array of bubble objects into ParsedMessage[].
445→ * Shared by both inline and headers-only code paths.
446→ */
447→function parseBubbles(conversation: Array<Record<string, unknown>>, sessionId: string): ParsedMessage[] {
448→  const messages: ParsedMessage[] = [];
449→
450→  for (let i = 0; i < conversation.length; i++) {
451→    const bubble = conversation[i];
452→
453→    // Determine message type
454→    let type: 'user' | 'assistant' | 'system';
455→    if (bubble.type === 1 || bubble.role === 'user') {
456→      type = 'user';
457→    } else if (bubble.type === 2 || bubble.role === 'assistant') {
458→      type = 'assistant';
459→    } else {
460→      type = 'system';
461→    }
462→
463→    // Extract content — prefer richText (markdown), fall back to text
464→    const content = ((bubble.richText || bubble.text || bubble.content || '') as string).toString();
465→    if (!content && type !== 'system') continue; // Skip empty messages
466→
467→    // Truncate to 10,000 chars (same as Claude Code parser)
468→    const truncatedContent = content.length > 10000 ? content.slice(0, 10000) : content;
469→
470→    // Extract timestamp (milliseconds)
471→    let timestamp: Date;
472→    if (bubble.createdAt) {
473→      timestamp = new Date(typeof bubble.createdAt === 'number' ? bubble.createdAt : Date.parse(bubble.createdAt as string));
474→    } else {
475→      timestamp = new Date(0); // Epoch fallback — filtered out of session bounds calculation
476→    }
477→
478→    // Extract tool calls from toolFormerData if present
479→    const toolCalls: ToolCall[] = [];
480→    if (bubble.toolFormerData) {
481→      try {
482→        const toolData = typeof bubble.toolFormerData === 'string'
483→          ? JSON.parse(bubble.toolFormerData) as Record<string, unknown>
484→          : bubble.toolFormerData as Record<string, unknown>;
485→        if (toolData.name || toolData.toolName) {
486→          toolCalls.push({
487→            id: (bubble.bubbleId as string) || `tool-${i}`,
488→            name: (toolData.name || toolData.toolName || 'unknown') as string,
489→            input: (toolData.input || toolData.arguments || {}) as Record<string, unknown>,
490→          });
491→        }
492→      } catch {
493→        // Ignore malformed tool data
494→      }
495→    }
496→
497→    // Extract tool calls from codeBlocks if they look like file edits
498→    // (Cursor stores applied code edits as codeBlocks)
499→    if (bubble.codeBlocks && Array.isArray(bubble.codeBlocks)) {
500→      for (const block of bubble.codeBlocks as Array<Record<string, unknown>>) {
501→        if (block.uri || block.filePath) {
502→          toolCalls.push({
503→            id: `codeblock-${i}-${toolCalls.length}`,
504→            name: 'Edit',
505→            input: {
506→              file_path: (block.uri || block.filePath || '') as string,
507→              code: ((block.code || '') as string).slice(0, 1000),
508→            },
509→          });
510→        }
511→      }
512→    }
513→
514→    messages.push({
515→      id: (bubble.bubbleId as string) || `cursor-${sessionId}-${i}`,
516→      sessionId: `cursor:${sessionId}`,
517→      type,
518→      content: truncatedContent,
519→      thinking: null, // Cursor doesn't expose thinking
520→      toolCalls,
521→      toolResults: [], // Not available from Cursor's format
522→      usage: null, // No per-message usage data
523→      timestamp,
524→      parentId: null,
525→    });
526→  }
527→
528→  return messages;
529→}
