26→/**
27→ * Get a provider by name
28→ */
29→export function getProvider(name: string): SessionProvider {
30→  const provider = providers.get(name);
31→  if (!provider) {
32→    throw new Error(`Unknown provider: ${name}`);
33→  }
34→  return provider;
35→}
36→
37→/**
38→ * Get all registered providers
39→ */
40→export function getAllProviders(): SessionProvider[] {
41→  return [...providers.values()];
42→}
