  1→import { execFileSync } from 'child_process';
  2→import { createHash } from 'crypto';
  3→import { homedir, hostname, platform, userInfo } from 'os';
  4→import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'fs';
  5→import { join } from 'path';
  6→
  7→const CONFIG_DIR = join(homedir(), '.code-insights');
  8→const DEVICE_ID_FILE = join(CONFIG_DIR, 'device-id');
  9→
 10→/**
 11→ * Get or create a persistent device ID.
 12→ * Stored in ~/.code-insights/device-id
 13→ */
 14→export function getDeviceId(): string {
 15→  // Check if device ID already exists
 16→  if (existsSync(DEVICE_ID_FILE)) {
 17→    const existingId = readFileSync(DEVICE_ID_FILE, 'utf-8').trim();
 18→    if (existingId) {
 19→      return existingId;
 20→    }
 21→  }
 22→
 23→  // Generate new device ID based on machine characteristics
 24→  const machineInfo = [
 25→    hostname(),
 26→    platform(),
 27→    userInfo().username,
 28→    process.arch,
 29→  ].join('-');
 30→
 31→  const deviceId = createHash('sha256')
 32→    .update(machineInfo)
 33→    .digest('hex')
 34→    .slice(0, 12);
 35→
 36→  // Persist the device ID
 37→  if (!existsSync(CONFIG_DIR)) {
 38→    mkdirSync(CONFIG_DIR, { recursive: true });
 39→  }
 40→  writeFileSync(DEVICE_ID_FILE, deviceId, 'utf-8');
 41→
 42→  return deviceId;
 43→}
 44→
 45→/**
 46→ * Get device information for session metadata
 47→ */
 48→export function getDeviceInfo(): {
 49→  deviceId: string;
 50→  hostname: string;
 51→  platform: string;
 52→  username: string;
 53→} {
 54→  return {
 55→    deviceId: getDeviceId(),
 56→    hostname: hostname(),
 57→    platform: platform(),
 58→    username: userInfo().username,
 59→  };
 60→}
 61→
 62→/**
 63→ * Get git remote URL for a project path.
 64→ * Returns null if not a git repo or no remote configured.
 65→ */
 66→export function getGitRemoteUrl(projectPath: string): string | null {
 67→  try {
 68→    // Use execFileSync for safety - no shell spawning
 69→    const result = execFileSync('git', ['remote', 'get-url', 'origin'], {
 70→      cwd: projectPath,
 71→      encoding: 'utf-8',
 72→      timeout: 5000,
 73→      stdio: ['pipe', 'pipe', 'pipe'], // Capture stderr
 74→    });
 75→    return normalizeGitUrl(result.trim());
 76→  } catch {
 77→    // Not a git repo or no origin remote
 78→    return null;
 79→  }
 80→}
 81→
 82→/**
 83→ * Normalize git URL to a canonical form.
 84→ * Handles SSH, HTTPS, and various formats.
 85→ *
 86→ * Examples:
 87→ * - git@github.com:user/repo.git -> github.com/user/repo
 88→ * - https://github.com/user/repo.git -> github.com/user/repo
 89→ * - ssh://git@github.com/user/repo -> github.com/user/repo
 90→ */
 91→function normalizeGitUrl(url: string): string {
 92→  let normalized = url;
 93→
 94→  // Remove .git suffix
 95→  normalized = normalized.replace(/\.git$/, '');
 96→
 97→  // Handle SSH format: git@github.com:user/repo
 98→  const sshMatch = normalized.match(/^git@([^:]+):(.+)$/);
 99→  if (sshMatch) {
100→    return `${sshMatch[1]}/${sshMatch[2]}`;
101→  }
102→
103→  // Handle SSH URL format: ssh://git@github.com/user/repo
104→  const sshUrlMatch = normalized.match(/^ssh:\/\/git@([^/]+)\/(.+)$/);
105→  if (sshUrlMatch) {
106→    return `${sshUrlMatch[1]}/${sshUrlMatch[2]}`;
107→  }
108→
109→  // Handle HTTPS format: https://github.com/user/repo
110→  const httpsMatch = normalized.match(/^https?:\/\/([^/]+)\/(.+)$/);
111→  if (httpsMatch) {
112→    return `${httpsMatch[1]}/${httpsMatch[2]}`;
113→  }
114→
115→  // Fallback - return as is
116→  return normalized;
117→}
118→
119→/**
120→ * Generate a stable project ID.
121→ *
122→ * Priority:
123→ * 1. Git remote URL (most stable across devices)
124→ * 2. Project path hash (fallback for non-git projects)
125→ */
126→export function generateStableProjectId(projectPath: string): {
127→  projectId: string;
128→  source: 'git-remote' | 'path-hash';
129→  gitRemoteUrl: string | null;
130→} {
131→  const gitRemoteUrl = getGitRemoteUrl(projectPath);
132→
133→  if (gitRemoteUrl) {
134→    // Use git remote URL for stable ID
135→    const projectId = createHash('sha256')
136→      .update(gitRemoteUrl)
137→      .digest('hex')
138→      .slice(0, 16);
139→
140→    return {
141→      projectId,
142→      source: 'git-remote',
143→      gitRemoteUrl,
144→    };
145→  }
146→
147→  // Fallback to path hash (will differ across devices)
148→  const projectId = createHash('sha256')
149→    .update(projectPath)
150→    .digest('hex')
151→    .slice(0, 16);
152→
153→  return {
154→    projectId,
155→    source: 'path-hash',
156→    gitRemoteUrl: null,
157→  };
158→}
