27→    sessions = db.prepare(
28→      `SELECT id, project_name, generated_title, custom_title, started_at, ended_at,
29→              message_count, estimated_cost_usd, session_character, source_tool
30→       FROM sessions WHERE id IN (${placeholders}) ORDER BY started_at DESC`,
31→    ).all(...sessionIds) as Record<string, unknown>[];
32→  } else if (projectId) {
33→    sessions = db.prepare(
34→      `SELECT id, project_name, generated_title, custom_title, started_at, ended_at,
35→              message_count, estimated_cost_usd, session_character, source_tool
36→       FROM sessions WHERE project_id = ? ORDER BY started_at DESC`,
37→    ).all(projectId) as Record<string, unknown>[];
38→  } else {
39→    return c.json({ error: 'sessionIds or projectId required' }, 400);
40→  }
41→
42→  const lines: string[] = ['# Code Insights Export', ''];
43→
44→  for (const s of sessions) {
45→    const title = (s.custom_title ?? s.generated_title ?? s.id) as string;
46→    lines.push(`## ${title}`);
47→    lines.push(`- **Started:** ${s.started_at}`);
48→    lines.push(`- **Ended:** ${s.ended_at}`);
49→    lines.push(`- **Messages:** ${s.message_count}`);
50→    if (s.estimated_cost_usd != null) {
51→      lines.push(`- **Cost:** $${Number(s.estimated_cost_usd).toFixed(4)}`);
52→    }
53→    lines.push('');
54→  }
55→
56→  const markdown = lines.join('\n');
57→  trackEvent('export', true, 'markdown');
58→  c.header('Content-Type', 'text/markdown');
59→  return c.body(markdown);
60→});
