317→/**
318→ * Find recurring patterns across multiple insights and write bidirectional links to SQLite.
319→ */
320→export async function findRecurringInsights(
321→  insights: Array<{
322→    id: string;
323→    type: string;
324→    title: string;
325→    summary: string;
326→    project_name: string;
327→    session_id: string;
328→  }>
329→): Promise<RecurringInsightResult> {
330→  if (!isLLMConfigured()) {
331→    return { success: false, groups: [], updatedCount: 0, error: 'LLM not configured.' };
332→  }
333→
334→  const candidates = insights
335→    .filter(i => i.type !== 'summary' && i.type !== 'prompt_quality')
336→    .slice(0, 200);
337→
338→  if (candidates.length < 2) {
339→    return {
340→      success: false,
341→      groups: [],
342→      updatedCount: 0,
343→      error: 'Need at least 2 non-summary insights to find patterns.',
344→    };
345→  }
346→
347→  try {
348→    const client = createLLMClient();
349→
350→    const insightData = candidates.map(i => ({
351→      id: i.id,
352→      type: i.type === 'technique' ? 'learning' : i.type,
353→      title: i.title,
354→      summary: i.summary.slice(0, 150),
355→      projectName: i.project_name,
356→      sessionId: i.session_id,
357→    }));
358→
359→    const prompt = `Analyze these insights from coding sessions and find groups of semantically similar or duplicate insights — ones that express the same learning or decision even if worded differently.
360→
361→RULES:
362→- Only group insights that are genuinely about the same concept/topic
363→- Insights in a group should be from DIFFERENT sessions (same sessionId = not recurring)
364→- A group must have at least 2 insights
365→- An insight can only belong to one group
366→- Provide a brief "theme" describing what the group shares
367→- If no recurring patterns exist, return an empty groups array
368→
369→INSIGHTS:
370→${JSON.stringify(insightData, null, 2)}
371→
372→Respond with valid JSON only:
373→{
374→  "groups": [
375→    {
376→      "insightIds": ["insight_abc", "insight_def"],
377→      "theme": "Brief description of the shared concept"
378→    }
379→  ]
380→}`;
381→
382→    const response = await client.chat([
383→      {
384→        role: 'system',
385→        content: 'You are an expert at identifying recurring patterns and themes across software development insights. You find semantically similar insights even when they are worded differently. Respond with valid JSON only.',
386→      },
387→      { role: 'user', content: prompt },
388→    ]);
389→
390→    const jsonMatch = response.content.match(/\{[\s\S]*\}/);
391→    if (!jsonMatch) {
392→      return { success: false, groups: [], updatedCount: 0, error: 'Failed to parse recurring insights response.' };
393→    }
394→
395→    const parsed = JSON.parse(jsonMatch[0]) as { groups: RecurringInsightGroup[] };
396→    const groups = parsed.groups || [];
397→
398→    const validIds = new Set(candidates.map(i => i.id));
399→    const validGroups = groups
400→      .map(g => ({
401→        ...g,
402→        insightIds: g.insightIds.filter(id => validIds.has(id)),
403→      }))
404→      .filter(g => g.insightIds.length >= 2);
405→
406→    if (validGroups.length === 0) {
407→      return {
408→        success: true,
409→        groups: [],
410→        updatedCount: 0,
411→        usage: response.usage
412→          ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
413→          : undefined,
414→      };
415→    }
416→
417→    // Build bidirectional links
418→    const linkMap = new Map<string, string[]>();
419→    for (const group of validGroups) {
420→      for (const id of group.insightIds) {
421→        const others = group.insightIds.filter(otherId => otherId !== id);
422→        const existing = linkMap.get(id) || [];
423→        linkMap.set(id, [...new Set([...existing, ...others])]);
424→      }
425→    }
426→
427→    // Write links to SQLite
428→    const db = getDb();
429→    const updateLinks = db.prepare(
430→      `UPDATE insights SET linked_insight_ids = ? WHERE id = ?`
431→    );
432→
433→    for (const [insightId, linkedIds] of linkMap.entries()) {
434→      updateLinks.run(JSON.stringify(linkedIds), insightId);
435→    }
436→
437→    return {
438→      success: true,
439→      groups: validGroups,
440→      updatedCount: linkMap.size,
441→      usage: response.usage
442→        ? { inputTokens: response.usage.inputTokens, outputTokens: response.usage.outputTokens }
443→        : undefined,
444→    };
445→  } catch (error) {
446→    return {
447→      success: false,
448→      groups: [],
449→      updatedCount: 0,
450→      error: error instanceof Error ? error.message : 'Failed to find recurring insights',
451→    };
452→  }
453→}
