657→
658→  const insertMany = db.transaction((rows: InsightRow[]) => {
659→    for (const row of rows) {
660→      insert.run(
661→        row.id,
662→        row.session_id,
663→        row.project_id,
664→        row.project_name,
665→        row.type,
666→        row.title,
667→        row.content,
