684→interface DeleteOptions {
685→  excludeTypes?: string[];
686→  includeOnlyTypes?: string[];
687→  excludeIds?: string[];
688→}
689→
690→/**
691→ * Delete insights for a session, with optional type and ID exclusions.
692→ */
693→function deleteSessionInsights(sessionId: string, opts: DeleteOptions): void {
694→  const db = getDb();
695→  const conditions: string[] = ['session_id = ?'];
696→  const params: (string | number)[] = [sessionId];
697→
698→  if (opts.excludeTypes && opts.excludeTypes.length > 0) {
699→    conditions.push(`type NOT IN (${opts.excludeTypes.map(() => '?').join(', ')})`);
700→    params.push(...opts.excludeTypes);
701→  }
702→
703→  if (opts.includeOnlyTypes && opts.includeOnlyTypes.length > 0) {
704→    conditions.push(`type IN (${opts.includeOnlyTypes.map(() => '?').join(', ')})`);
705→    params.push(...opts.includeOnlyTypes);
706→  }
707→
708→  if (opts.excludeIds && opts.excludeIds.length > 0) {
709→    conditions.push(`id NOT IN (${opts.excludeIds.map(() => '?').join(', ')})`);
710→    params.push(...opts.excludeIds);
711→  }
712→
713→  db.prepare(`DELETE FROM insights WHERE ${conditions.join(' AND ')}`).run(...params);
714→}
