180→
181→function extractJsonPayload(response: string): string | null {
182→  const tagged = response.match(/<json>\s*([\s\S]*?)\s*<\/json>/i);
183→  if (tagged?.[1]) return tagged[1].trim();
184→  const jsonMatch = response.match(/\{[\s\S]*\}/);
185→  return jsonMatch ? jsonMatch[0] : null;
186→}
187→
188→/**
189→ * Parse the LLM response into structured insights.
190→ */
191→export function parseAnalysisResponse(response: string): AnalysisResponse | null {
192→  try {
193→    const jsonPayload = extractJsonPayload(response);
194→    if (!jsonPayload) {
195→      console.error('No JSON found in analysis response');
196→      return null;
197→    }
198→
199→    const parsed = JSON.parse(jsonPayload) as AnalysisResponse;
200→
201→    if (!parsed.summary || typeof parsed.summary.title !== 'string') {
202→      console.error('Invalid analysis response structure');
203→      return null;
204→    }
205→
206→    parsed.decisions = parsed.decisions || [];
207→    parsed.learnings = parsed.learnings || [];
208→
209→    return parsed;
210→  } catch (error) {
211→    console.error('Failed to parse analysis response:', error);
212→    return null;
213→  }
214→}
