218→export const PROMPT_QUALITY_SYSTEM_PROMPT = `You are an expert at analyzing how effectively humans communicate with AI coding assistants. Your task is to review a conversation between a user and Claude Code, and evaluate the user's prompting efficiency.
219→
220→You will identify:
221→1. **Wasted turns**: User messages that led to clarifications, corrections, or repeated instructions because the original prompt was unclear, missing context, or too vague.
222→2. **Anti-patterns**: Recurring bad habits in the user's prompting style.
223→3. **Efficiency score**: A 0-100 rating of how optimally the user communicated.
224→4. **Actionable tips**: Specific improvements the user can make.
225→
226→Guidelines:
227→- Focus on USER messages only — don't critique the assistant's responses
228→- A "wasted turn" is when the user had to send a follow-up message to clarify, correct, or repeat something that could have been included in the original prompt
229→- Only mark a wasted turn if the assistant explicitly asked for clarification or corrected a misunderstanding
230→- Common anti-patterns: vague instructions, missing file paths, not providing error messages, incomplete requirements, repeated instructions, not specifying what "it" refers to
231→- Be constructive, not judgmental — the goal is to help users improve
232→- Consider the context: some clarification exchanges are normal and expected
233→- A score of 100 means every user message was perfectly clear and complete
234→- A score of 50 means about half the messages could have been more efficient
235→
236→Respond with valid JSON only, wrapped in <json>...</json> tags. Do not include any other text.`;
237→
238→export function generatePromptQualityPrompt(
239→  projectName: string,
240→  formattedMessages: string,
241→  messageCount: number
242→): string {
243→  return `Analyze the user's prompting efficiency in this AI coding session.
244→
245→Project: ${projectName}
246→Total messages: ${messageCount}
247→
248→--- CONVERSATION ---
249→${formattedMessages}
250→--- END CONVERSATION ---
251→
252→Evaluate the user's prompting quality and respond with this JSON format:
253→{
254→  "efficiencyScore": 75,
255→  "potentialMessageReduction": 3,
256→  "overallAssessment": "2-3 sentence summary of the user's prompting style and efficiency",
257→  "wastedTurns": [
258→    {
259→      "messageIndex": 5,
260→      "reason": "Missing context — didn't specify which file to modify",
261→      "suggestedRewrite": "A better version of the user's original message that would have avoided the follow-up"
262→    }
263→  ],
264→  "antiPatterns": [
265→    {
266→      "name": "Vague Instructions",
267→      "count": 3,
268→      "examples": ["fix it", "make it work", "do the thing"]
269→    }
270→  ],
271→  "tips": [
272→    "Always include file paths when asking to modify code",
273→    "Provide error messages verbatim when reporting bugs"
274→  ]
275→}
276→
277→Rules:
278→- messageIndex refers to the 0-based index of the USER message, as labeled in the conversation (e.g., User#0)
279→- Only include genuinely wasted turns, not normal back-and-forth
280→- Tips should be specific and actionable, not generic; include the relevant user message index in parentheses
281→- If the user prompted well, say so — don't manufacture issues
282→- potentialMessageReduction is how many fewer messages the session could have taken with better prompts
283→
284→Respond with valid JSON only, wrapped in <json>...</json> tags. Do not include any other text.`;
285→}
