287→export interface WastedTurn {
288→  messageIndex: number;
289→  reason: string;
290→  suggestedRewrite: string;
291→}
292→
293→export interface AntiPattern {
294→  name: string;
295→  count: number;
296→  examples: string[];
297→}
298→
299→export interface PromptQualityResponse {
300→  efficiencyScore: number;
301→  potentialMessageReduction: number;
302→  overallAssessment: string;
303→  wastedTurns: WastedTurn[];
304→  antiPatterns: AntiPattern[];
305→  tips: string[];
306→}
307→
308→export function parsePromptQualityResponse(response: string): PromptQualityResponse | null {
309→  try {
310→    const jsonPayload = extractJsonPayload(response);
311→    if (!jsonPayload) {
312→      console.error('No JSON found in prompt quality response');
313→      return null;
314→    }
315→
316→    const parsed = JSON.parse(jsonPayload) as PromptQualityResponse;
317→
318→    if (typeof parsed.efficiencyScore !== 'number') {
319→      console.error('Invalid prompt quality response: missing efficiencyScore');
320→      return null;
321→    }
322→
323→    parsed.efficiencyScore = Math.max(0, Math.min(100, Math.round(parsed.efficiencyScore)));
324→    parsed.potentialMessageReduction = parsed.potentialMessageReduction || 0;
325→    parsed.overallAssessment = parsed.overallAssessment || '';
326→    parsed.wastedTurns = parsed.wastedTurns || [];
327→    parsed.antiPatterns = parsed.antiPatterns || [];
328→    parsed.tips = parsed.tips || [];
329→
330→    return parsed;
331→  } catch (error) {
332→    console.error('Failed to parse prompt quality response:', error);
333→    return null;
334→  }
335→}
